18	using namespace SDKBleKeyV3;
19	    
20	BLEKeyV3Message * nextBleKeyV3Message(const uint8_t *data,size_t dataSize) {
21	    if (data == NULL || dataSize < 0) {
22	        return NULL;
23	    }
24	    size_t msgSize = sizeOfBLEKeyV3Message((BLEKeyV3Message *)data);
25	    if (!msgSize || msgSize > dataSize) {
26	        return NULL;
27	    }
28	    
29	    BLEKeyV3Message *v3Message = (BLEKeyV3Message *)malloc(sizeof(BLEKeyV3Message));
30	    memcpy((uint8_t *)v3Message+offsetof(BLEKeyV3Message, msgId), data, sizeof(v3Message->msgId));
31	    memcpy((uint8_t *)v3Message+offsetof(BLEKeyV3Message, msgLength), data+offsetof(BLEKeyV3Message, msgLength), sizeof(v3Message->msgLength));
32	    v3Message->messageData = (uint8_t *)malloc(v3Message->msgLength);
33	    memcpy(v3Message->messageData, data+offsetof(BLEKeyV3Message, messageData), v3Message->msgLength);
34	    memcpy((uint8_t *)v3Message+offsetof(BLEKeyV3Message, checkSum), data+offsetof(BLEKeyV3Message, messageData)+v3Message->msgLength, sizeof(v3Message->checkSum));
35	    return v3Message;
36	}
37	
38	BLEKeyV3Conent * nextBleKeyV3Content(const void *data,size_t dataSize) {
39	    if (data == NULL || dataSize == 0) {
40	        return NULL;
41	    }
42	    uint8_t *tlv = (uint8_t *)tlvMessageGetNext(data, dataSize);
43	    if (!tlv) {
44	        return NULL;
45	    }
46	    size_t totalSize = getTlvTotalSize(tlv);
47	    if (!totalSize || totalSize > dataSize) {
48	        return NULL;
49	    }
50	    tlvTag tlvTag = getTlvTag(tlv);
51	    tlvLength tlvLength = getTlvLength(tlv);
52	    uint8_t *tlvData = (uint8_t *)getTlvDataValue(tlv);
53	    if (!tlvTag.tagSize || !tlvTag.tag || !tlvLength.lenSize || !tlvLength.dataSize || !tlvData) {
54	        safe_free(tlv);
55	        return NULL;
56	    } else {
57	        BLEKeyV3Conent *v3Content = (BLEKeyV3Conent *)malloc(sizeof(BLEKeyV3Conent));
58	        v3Content->contentType = (BLEKeyV3ContentType)tlvTag.tagSize;
59	        v3Content->contentSize = totalSize;
60	        v3Content->tag = tlvTag.tag;
61	        v3Content->contentDataLength = tlvLength.dataSize;
62	        v3Content->contentData = (uint8_t *)malloc(tlvLength.dataSize);
63	        memcpy(v3Content->contentData, tlvData, tlvLength.dataSize);
64	        safe_free(tlv);
65	        return v3Content;
66	    }
67	}
68	
69	void handleSpecialLargeContentData(uint8_t *data,uint8_t dataSize,uint16_t tag,BleKeyV3OutputMessage *outputMessage) {
70	    __CHECK(outputMessage != NULL);
71	    switch (tag) {
72	        case BLEKeyV3CarStateTypeCommon:
73	        {
