332	void handleXPBleKeyV3Content(BLEKeyV3Conent *content,BleKeyV3OutputMessage *outputMessage) {
333	    if (content->contentType == BLEKeyV3ContentTypeDualType) {
334	        uint8_t *contentData = (uint8_t *)content->contentData;
335	        handleDualTlvNormalData(content->tag, outputMessage);
336	        while (contentData) {
337	            BLEKeyV3Conent *level2Content = nextBleKeyV3Content(contentData, content->contentDataLength);
338	            if (level2Content && isEffectiveBLEKeyV3ContentData(level2Content)) {
339	                handleTlvLevel2Data(level2Content,outputMessage);
340	                contentData = contentData + level2Content->contentSize;
341	                free(level2Content->contentData);
342	                level2Content->contentData = NULL;
343	                safe_free(level2Content);
344	            } else {
345	                break;
346	            }
347	        }
348	    } else {
349	        uint8_t tag = (uint8_t)content->tag;
350	        uint8_t vaildTag = tag & 0xF0;
351	        if (vaildTag >= BLEKeyV3CarStateTypeCommon && vaildTag <= BLEKeyV3CarStateTypeParkingLimitControlState) {
352	            handleSpecialLargeContentData(content->contentData,content->contentDataLength,tag,outputMessage);
353	        } else {
