359	void handleBleKeyV3Message(BleKeyV3CanMessageParams *v3CanMessageParams,BleKeyV3OutputMessageParams *outputMessageParams,BLEKeyV3Message *message,uint8_t messageSize) {
360	    if (!message || !message->messageData || !messageSize) {
361	        return;
362	    }
363	    uint8_t *decodeData = (uint8_t *)malloc(256);
364	    uint32_t decodeDataSize =  message->msgLength;
365	    if (!v3CanMessageParams->isEncrypted) {
366	        memcpy(decodeData, message->messageData, decodeDataSize);
367	    } else {
368	        switch (message->msgId) {
369	            case BLEKeyV3MessageTypeAuth0:
370	            {
371	                unsigned char iv_copy[16];
372	                memcpy(iv_copy, bleKeyV3IvData, 16);
373	                unsigned char *plainText = aes_256_cbc_decrypt((unsigned char *)message->messageData, message->msgLength, (unsigned char *)v3CanMessageParams->authKeyMessage.value, (unsigned char *)iv_copy);
374	                memcpy(decodeData, plainText, decodeDataSize);
375	                safe_free(plainText);
376	            }
377	                break;
378	            case BLEKeyV3MessageTypeAuth1:
379	            case BLEKeyV3MessageTypeRKE:
380	            case BLEKeyV3MessageTypeNotification:
381	            {
382	                uint32_t resultSize = 0;
383	                uint8_t *xorResult = getXorResult(&resultSize, message->messageData, message->msgLength, (uint8_t *)v3CanMessageParams->sessionKeyMessage.value, v3CanMessageParams->sessionKeyMessage.len);
384	                memcpy(decodeData, xorResult, resultSize);
385	                safe_free(xorResult);
386	                decodeDataSize = resultSize;
387	            }
388	                break;
389	                
390	            default:
391	                break;
392	        }
393	    }
394	    uint8_t *messaageData = decodeData;
395	    
396	    while (decodeDataSize > 0) {
397	        BLEKeyV3Conent *content = nextBleKeyV3Content(messaageData,decodeDataSize);
398	        if (content && isEffectiveBLEKeyV3ContentData(content)) {
399	            if (outputMessageParams->outputSize == outputMessageParams->capacity) {
400	                int newCapacity = outputMessageParams->capacity * 2;
401	                BleKeyV3OutputMessage *newItems = (BleKeyV3OutputMessage *)realloc(outputMessageParams->outputMessages, newCapacity * sizeof(BleKeyV3OutputMessage));
402	                outputMessageParams->outputMessages = newItems;
403	                outputMessageParams->capacity = newCapacity;
404	            }
405	            BleKeyV3OutputMessage *outputMessage = &(outputMessageParams->outputMessages[outputMessageParams->outputSize]);
406	            outputMessageParams->outputSize += 1;
407	            handleXPBleKeyV3Content(content,outputMessage);
408	            messaageData = messaageData + content->contentSize;
409	            decodeDataSize = decodeDataSize - content->contentSize;
410	            free(content->contentData);
411	            content->contentData = NULL;
412	            safe_free(content);
413	        } else {
414	            break;
415	        }
416	    }
417	    safe_free(decodeData);
418	}
