420	void decodeBleKeyV3CanMessage(BleKeyV3CanMessageParams *v3CanMessageParams,BleKeyV3OutputMessageParams *outputMessageParams) {
421	    if (v3CanMessageParams == NULL) {
422	        outputMessageParams->result = BleKeyV3DecodeV3CanMessageDataIsNull;
423	        return ;
424	    }
425	    if (v3CanMessageParams->canMessage.value == NULL || v3CanMessageParams->canMessage.len == 0) {
426	        outputMessageParams->result = BleKeyV3DecodeV3CanMessageDataIsNull;
427	        return ;
428	    }
429	    int isEected = isEffectiveBLEKeyV3MessageData((BLEKeyV3Message *)v3CanMessageParams->canMessage.value,v3CanMessageParams->canMessage.len);
430	    if (isEected) {
431	        outputMessageParams->capacity = BleKeyV3CanMessageMaxCount;
432	        outputMessageParams->outputMessages = (BleKeyV3OutputMessage *)calloc(BleKeyV3CanMessageMaxCount, sizeof(BleKeyV3OutputMessage));
433	        size_t dataSize = v3CanMessageParams->canMessage.len;
434	        uint8_t *messageData = v3CanMessageParams->canMessage.value;
435	        while (dataSize > 0) {
436	            BLEKeyV3Message *message = nextBleKeyV3Message(messageData, dataSize);
437	            if (message) {
438	                size_t msgSize = sizeOfBLEKeyV3Message(message);
439	                handleBleKeyV3Message(v3CanMessageParams,outputMessageParams,message,msgSize);
440	                messageData = messageData + msgSize;
441	                dataSize -= msgSize;
442	                free(message->messageData);
443	                message->messageData = NULL;
444	                safe_free(message);
445	            } else {
446	                break;
447	            }
448	        }
449	        outputMessageParams->result = BleKeyV3DecodeV3CanMessageSuccess;
450	    } else {
451	        outputMessageParams->result = BleKeyV3DecodeV3CanMessageNotExpectedData;
452	    }
453	}
