457	    for (int i = 0; i<outputMessageParams->outputSize; i++) {
458	        BleKeyV3OutputMessage *outputMessage = &(outputMessageParams->outputMessages[i]);
459	        if (outputMessage->messageData.len > 0 && outputMessage->messageData.value != NULL) {
460	            free(outputMessage->messageData.value);
461	            outputMessage->messageData.value = NULL;
462	        }
463	    }
464	    free(outputMessageParams->outputMessages);
465	    outputMessageParams->outputMessages = NULL;
466	}
