#include <stdio.h>
#include <cstdint>

static const int BleKeyV3CanMessageMaxCount = 10;

typedef enum BleKeyV3DecodeV3CanMessageResult: uint8_t {
    BleKeyV3DecodeV3CanMessageSuccess     = 0x0,
    BleKeyV3DecodeV3CanMessageDataIsNull,
    BleKeyV3DecodeV3CanMessageAuthKeyIsNull,
    BleKeyV3DecodeV3CanMessageSessionKeyIsNull,
    BleKeyV3DecodeV3CanMessageNotExpectedData
}BleKeyV3DecodeV3CanMessageResult;

typedef enum BleKeyV3OutputMessageType: uint8_t {
    BleKeyV3OutputMessageTypeAuth0Response = 0x01,      //auth0
    BleKeyV3OutputMessageTypeCommonStatus,              //通用类status
    BleKeyV3OutputMessageTypeCommonErrorCode,           //通用类errorCode
    BleKeyV3OutputMessageTypeCommonErrorReason,         //通用类reason
    BleKeyV3OutputMessageTypeRkeResponse,               //rkeResponse
    BleKeyV3OutputMessageTypeCommonCarState,            //D0
    BleKeyV3OutputMessageTypeChargeState,               //D1
    BleKeyV3OutputMessageTypeParkingState,              //D2
    BleKeyV3OutputMessageTypeNumeric,                   //D3
    BleKeyV3OutputMessageTypeSelfCalibration,           //D4
    BleKeyV3OutputMessageTypeRssiCollect,               //D6
    BleKeyV3OutputMessageTypeParkingControlState,       //D8
    BleKeyV3OutputMessageTypePollingFuncState,          //D9
    BleKeyV3OutputMessageTypeUnknown = 0xFF
}BleKeyV3OutputMessageType;

//base
typedef struct BleKeyV3NumericBaseMessage {
    uint8_t len;
    uint64_t value;
}__attribute__((packed)) BleKeyV3NumericBaseMessage;

typedef struct BleKeyV3ByteBaseMessage {
    uint8_t len;
    uint8_t *value;
}__attribute__((packed)) BleKeyV3ByteBaseMessage;

typedef struct BleKeyV3CanMessageParams {
    uint8_t isEncrypted;
    BleKeyV3ByteBaseMessage canMessage;
    BleKeyV3ByteBaseMessage authKeyMessage;
    struct {
        int len;
        uint8_t *value;
    }sessionKeyMessage;
}__attribute__((packed)) BleKeyV3CanMessageParams;

typedef struct BleKeyV3OutputMessage {
    BleKeyV3OutputMessageType messageType;
    BleKeyV3ByteBaseMessage messageData;
}__attribute__((packed)) BleKeyV3OutputMessage;

typedef struct BleKeyV3OutputMessageParams {
    BleKeyV3DecodeV3CanMessageResult result = BleKeyV3DecodeV3CanMessageSuccess;
    int outputSize = 0;
    int capacity = 0;
    BleKeyV3OutputMessage *outputMessages = NULL;
}__attribute__((packed)) BleKeyV3OutputMessageParams;

//车态全量D0
#define SUB_EXT_DOOR_STATE_INDEX 64
#define SUPER_LOCK_STATE 73
#define TRAILER_HOOK_SYSTEM_STATE 87
#define TRAILER_HOOK_STATE 75

typedef struct BleKeyV3CarStateD0 {
    uint8_t leftFrontDoorState;
    uint8_t rightFrontDoorState;
    uint8_t leftBackDoorState;
    uint8_t rightBackDoorState;
    uint8_t bonnetAjarState;
    uint8_t trunckState;
    uint8_t trunckActionState;
    uint8_t leftSlideState;
    uint8_t leftSlideOpenDegree;
    uint8_t rightSlideState;
    uint8_t rightSlideOpenDegree;
    uint8_t empennageState;
    uint8_t empennageOpenDegree;
    uint8_t lockState;
    uint8_t tempeoryLockState;
    uint8_t chargePortLockState;
    uint8_t leftFrontWindowDegree;
    uint8_t rightFrontWindowDegree;
    uint8_t leftBackWindowDegree;
    uint8_t rightBackWindowDegree;
    uint8_t leftTurnSignalState;
    uint8_t rightTurnSignalState;
    uint8_t lightSoundState;
    uint8_t driverSeatOccupied;
    uint8_t psngerSeatOccupied;
    uint8_t secondLeftSeatOccupied;
    uint8_t secondMiddleSeatOccupied;
    uint8_t secondRightSeatOccupied;
    uint8_t thirdLeftSeatOccupied;
    uint8_t thirdMiddleSeatOccupied;
    uint8_t thirdRightSeatOccupied;
    uint8_t driverSeatBeltState;
    uint8_t psngrSeatBeltState;
    uint8_t secondLeftSeatBeltState;
    uint8_t secondMiddleSeatBeltState;
    uint8_t secondRightSeatBeltState;
    uint8_t thirdLeftSeatBeltState;
    uint8_t thirdMiddleSeatBeltState;
    uint8_t thirdRightSeatBeltState;
    uint8_t reverse1[24];
    uint8_t mainExtDoorState;
    uint8_t subExtDoorState;
    uint8_t reverse2[SUPER_LOCK_STATE - SUB_EXT_DOOR_STATE_INDEX -1];
    uint8_t superLockState;
    uint8_t trailerHookMachineState;
    uint8_t trailerHookState;
    uint8_t reverse3[TRAILER_HOOK_SYSTEM_STATE - TRAILER_HOOK_STATE - 1];
    uint8_t trailerHookSystemState;
    uint8_t leftFrontElecDoorState;
    uint8_t leftBackElecDoorState;
