    uint8_t parkingRCLAreaLevel;   // 右侧车道区域水平
    uint8_t parkingRCRAreaLevel;   // 右侧车道区域水平
    uint8_t parkingRORAreaLevel;   // 右侧后面区域水平
    uint8_t parkingFSLAreaLevel;   // 左侧面前区域水平
    uint8_t parkingFSRAreaLevel;   // 左侧侧面区域水平
    uint8_t parkingFOLAreaLevel;   // 左侧后面区域水平
    uint8_t parkingFCLAreaLevel;   // 左侧车道区域水平
    uint8_t parkingFCRAreaLevel;   // 右侧车道区域水平
    uint8_t parkingFORAreaLevel;   // 右侧车道区域水平

}__attribute__((packed)) BleKeyV3CarStateD2;

//数量类D3
typedef struct BleKeyV3CarStateD3 {
    uint32_t totalDistances;
    uint8_t vcuMileage;
    uint16_t totalBatteryLife;
    uint16_t carSpeed;
    uint8_t carSpeedState;
}__attribute__((packed)) BleKeyV3CarStateD3;

//自标定结果类D4
typedef struct BleKeyV3CarStateD4 {
    uint8_t result;
    BleKeyV3ByteBaseMessage resultData;
    uint8_t direction;
    uint8_t distance;
    uint32_t uid;
    BleKeyV3ByteBaseMessage deviceModel;
}__attribute__((packed)) BleKeyV3CarStateD4;

//标定结果类D6
typedef struct BleKeyV3CarStateD6 {
    uint8_t result;
    uint8_t direction;
    uint8_t distance;
    uint32_t uid;
    BleKeyV3ByteBaseMessage deviceModel;
}__attribute__((packed)) BleKeyV3CarStateD6;

typedef struct BleKeyV3CarStateD8 {
    uint8_t result;
}__attribute__((packed)) BleKeyV3CarStateD8;

typedef struct BleKeyV3CarStateD9 {
    uint8_t pollingUnlockState;
}__attribute__((packed)) BleKeyV3CarStateD9;


//rkeResponse类
typedef struct BleKeyV3RkeResponse {
    BleKeyV3NumericBaseMessage rkeId;
    BleKeyV3NumericBaseMessage status;
    BleKeyV3NumericBaseMessage errorCode;
    BleKeyV3ByteBaseMessage errorReason;
}__attribute__((packed)) BleKeyV3RkeResponse;

// auth0Response
typedef struct BleKeyV3Auth0Response {
    BleKeyV3NumericBaseMessage rand01;
    BleKeyV3NumericBaseMessage rand1;
}__attribute__((packed)) BleKeyV3Auth0Response;

void decodeBleKeyV3CanMessage(BleKeyV3CanMessageParams *v3CanMessageParams,BleKeyV3OutputMessageParams *outputMessageParams);

void freeBleV3OutputMessages(BleKeyV3OutputMessageParams *outputMessageParams);

