17	BleKeyV3Auth0RequestCreateResult getAuth0FactorTlvData(uint64_t uid, const uint8_t *keyIdData,size_t keyIdSize, uint32_t r0,uint64_t timeStamp,uint8_t **authFactorTlvResultData) {
18	    __CHECK_RET(keyIdData != NULL && keyIdSize != 0,BleKeyV3Auth0RequestCreateKeyIdIsNull)
19	    uint64_t uidLittleEndian = host_int64_to_little_endian(uid);
20	    uint8_t *uidTlvData = (uint8_t *)encodeTlvMessage(BLEKeyV3Auth0RequestFactorTypeUid, sizeof(uint64_t), &uidLittleEndian);
21	    
22	    uint8_t *keyIdTlvData = (uint8_t *)encodeTlvMessage(BLEKeyV3Auth0RequestFactorTypeKid,keyIdSize,keyIdData);
23	    
24	    uint32_t r0LittleEndian = host_int32_to_little_endian(r0);
25	    uint8_t *r0TlvData = (uint8_t *)encodeTlvMessage(BLEKeyV3Auth0RequestFactorTypeRand0, sizeof(uint32_t), &r0LittleEndian);
26	    
27	    uint64_t timeStampLittleEndian = host_int64_to_little_endian(timeStamp);
28	    uint8_t *timeStampTlvData = (uint8_t *)encodeTlvMessage(BLEKeyV3Auth0RequestFactorTypeTimeStamp, sizeof(uint64_t), &timeStampLittleEndian);
29	    size_t uidTlvDataSize = getTlvTotalSize(uidTlvData);
30	    size_t keyIdTlvDataSize = getTlvTotalSize(keyIdTlvData);
31	    size_t r0TlvDataSize = getTlvTotalSize(r0TlvData);
32	    size_t timeStampTlvDataSize = getTlvTotalSize(timeStampTlvData);
33	    size_t authFactorLength = uidTlvDataSize + keyIdTlvDataSize + r0TlvDataSize + timeStampTlvDataSize;
34	    uint8_t *authFactorData = (uint8_t *)malloc(authFactorLength);
35	    size_t offset = 0;
36	    memcpy(authFactorData+offset, uidTlvData, uidTlvDataSize);
37	    offset += uidTlvDataSize;
38	    memcpy(authFactorData+offset, keyIdTlvData, keyIdTlvDataSize);
39	    offset += keyIdTlvDataSize;
40	    memcpy(authFactorData+offset, r0TlvData, r0TlvDataSize);
41	    offset += r0TlvDataSize;
42	    memcpy(authFactorData+offset, timeStampTlvData,timeStampTlvDataSize);
43	    offset += timeStampTlvDataSize;
44	    safe_free(uidTlvData);
45	    safe_free(keyIdTlvData);
46	    safe_free(r0TlvData);
47	    safe_free(timeStampTlvData);
48	    uint8_t *authFactorTlvData = (uint8_t *)encodeTlvMessage(BLEKeyV3AuthDataTypeAuth0RequestFactor, authFactorLength, authFactorData);
49	    safe_free(authFactorData);
50	    *authFactorTlvResultData =  authFactorTlvData;
51	    return BleKeyV3Auth0RequestCreateSuccess;
52	}
53	
54	BleKeyV3Auth1RequestCreateResult getAuth1FactorTlvData(uint32_t r12,uint8_t *certMessageData,size_t certMessageLength,uint8_t **authFactorTlvResultData) {
55	    __CHECK_RET(certMessageData != NULL && certMessageLength != 0,BleKeyV3Auth1RequestCreateCertMessageIsNull)
56	    uint32_t r12LittleEndian = host_int32_to_little_endian(r12);
57	    uint8_t *r12TlvData = (uint8_t *)encodeTlvMessage(BLEKeyV3Auth1RequestFactorTypeRand12, sizeof(r12LittleEndian), &r12LittleEndian);
58	    uint8_t *certMessageTlvData = (uint8_t *)encodeTlvMessage(BLEKeyV3Auth1RequestFactorTypeCertMessage, certMessageLength, certMessageData);
59	    size_t r12TlvDataSize = getTlvTotalSize(r12TlvData);
60	    size_t certMessageTlvDataSize = getTlvTotalSize(certMessageTlvData);
61	    size_t authFactorLength = r12TlvDataSize + certMessageTlvDataSize;
62	    uint8_t *authFactorData = (uint8_t *)malloc(authFactorLength);
63	    size_t offset = 0;
64	    memcpy(authFactorData+offset, r12TlvData, r12TlvDataSize);
65	    offset += r12TlvDataSize;
66	    memcpy(authFactorData+offset, certMessageTlvData, getTlvTotalSize(certMessageTlvData));
67	    offset += certMessageTlvDataSize;
68	    safe_free(r12TlvData);
69	    safe_free(certMessageTlvData);
70	    uint8_t *authFactorTlvData = (uint8_t *)encodeTlvMessage(BLEKeyV3AuthDataTypeAuth1RequestFactor, authFactorLength, authFactorData);
71	    safe_free(authFactorData);
72	    *authFactorTlvResultData = authFactorTlvData;
73	    return BleKeyV3Auth1RequestCreateSuccess;
74	}
75	
76	uint8_t * getPollingCustomeData(BleKeyV3PollingConfigParams *pollingConfigParams, uint8_t tag) {
77	    size_t pollingDataHeaderLength = sizeof(BleKeyV3PollingConfigParams) - sizeof(pollingConfigParams->selfCalibrationData);
78	    size_t pollingDataLength = 0;
79	    if (pollingConfigParams->selfCalibrationLen != 0) {
80	        pollingDataLength = pollingConfigParams->selfCalibrationLen;
81	    }
82	    uint8_t *pollingData = (uint8_t *)malloc(pollingDataHeaderLength+pollingDataLength);
83	    memcpy(pollingData, pollingConfigParams, pollingDataHeaderLength);
84	    if (pollingConfigParams->selfCalibrationLen != 0) {
85	        memcpy(pollingData+pollingDataHeaderLength, pollingConfigParams->selfCalibrationData, pollingConfigParams->selfCalibrationLen);
86	    }
87	    uint8_t *pollingTlvData = (uint8_t *)encodeTlvMessage(tag, pollingDataHeaderLength+pollingDataLength, pollingData);
88	    safe_free(pollingData);
89	    return pollingTlvData;
90	}
