92	BleKeyV3Auth0RequestCreateResult getPollingConfigTlvData(BleKeyV3PollingConfigParams *pollingConfigParams, uint8_t pollingEnableSwitch, uint8_t *deviceModelData, size_t deviceModelLen, uint8_t *bleNameData, size_t bleNameLen, uint8_t **pollingConfigTlvResultData) {
93	    __CHECK_RET(deviceModelData != NULL && deviceModelLen != 0,BleKeyV3Auth0RequestCreateDeviceModelIsNull)
94	    __CHECK_RET(bleNameData != NULL && bleNameLen != 0,BleKeyV3Auth0RequestCreateDeviceNameIsNull)
95	    uint8_t *pollingTlvData = getPollingCustomeData(pollingConfigParams, BLEKeyV3Auth0RequestPollingConfigTypeCustomeRssi);
96	    uint8_t *deviceModelTlvData = (uint8_t *)encodeTlvMessage(BLEKeyV3Auth0RequestPollingConfigTypeDeviceModel, deviceModelLen, deviceModelData);
97	    uint8_t *bleNameTlvData = (uint8_t *)encodeTlvMessage(BLEKeyV3Auth0RequestPollingConfigTypeBleName, bleNameLen, bleNameData);
98	    uint8_t *pollingEnableConfigTlvData = (uint8_t *)encodeTlvMessage(BLEKeyV3Auth0RequestPollingConfigEnableSwitch, sizeof(pollingEnableSwitch), &pollingEnableSwitch);
99	
100	    size_t pollingTlvDataSize = getTlvTotalSize(pollingTlvData);
101	    size_t deviceModelTlvDataSize = getTlvTotalSize(deviceModelTlvData);
102	    size_t bleNameTlvDataSize = getTlvTotalSize(bleNameTlvData);
103	    size_t pollingEnableConfigTlvDataSize = getTlvTotalSize(pollingEnableConfigTlvData);
104	    uint8_t pollingConfigLenth = pollingTlvDataSize + deviceModelTlvDataSize + bleNameTlvDataSize + pollingEnableConfigTlvDataSize;
105	    uint8_t *pollingConfigData = (uint8_t *)malloc(pollingConfigLenth);
106	    uint8_t offset = 0;
107	    memcpy(pollingConfigData+offset, pollingTlvData, pollingTlvDataSize);
108	    offset += pollingTlvDataSize;
109	    memcpy(pollingConfigData+offset, deviceModelTlvData, deviceModelTlvDataSize);
110	    offset += deviceModelTlvDataSize;
111	    memcpy(pollingConfigData+offset, bleNameTlvData, bleNameTlvDataSize);
112	    offset += bleNameTlvDataSize;
113	    memcpy(pollingConfigData+offset, pollingEnableConfigTlvData, pollingEnableConfigTlvDataSize);
114	    offset += pollingEnableConfigTlvDataSize;
115	    
116	    safe_free(pollingTlvData);
117	    safe_free(deviceModelTlvData);
118	    safe_free(bleNameTlvData);
119	    safe_free(pollingEnableConfigTlvData);
120	    uint8_t *pollingConfigTlvData = (uint8_t *)encodeTlvMessage(BLEKeyV3AuthDataTypePollingConfig, pollingConfigLenth, pollingConfigData);
121	    safe_free(pollingConfigData);
122	    *pollingConfigTlvResultData = pollingConfigTlvData;
123	    return BleKeyV3Auth0RequestCreateSuccess;
124	}
125	
126	BleKeyV3RkeRequestCreateResult getRKEDataWithRkeType(BLEKeyV3RKERequestType rkeType,uint8_t controlId,uint8_t *controlData,size_t controlDataSize,uint8_t **rkeTlvResultData) {
127	    __CHECK_RET(controlData != NULL && controlDataSize != 0,BleKeyV3RkeRequestCreateRkeDataIsNull)
128	    uint8_t *controlIdTlvData = (uint8_t *)encodeTlvMessage(BLEKeyV3RKEDataTypeControlId, sizeof(uint8_t), &controlId);
129	    uint8_t *controlDataTlvData = (uint8_t *)encodeTlvMessage(BLEKeyV3RKEDataTypeControlData, controlDataSize, controlData);
130	    size_t controlIdTlvDataSize = getTlvTotalSize(controlIdTlvData);
131	    size_t controlDataTlvDataSize = getTlvTotalSize(controlDataTlvData);
132	    size_t rkeDataLength = controlIdTlvDataSize +controlDataTlvDataSize;
133	    uint8_t *rkeData = (uint8_t *)malloc(rkeDataLength);
134	    uint8_t offset = 0;
135	    memcpy(rkeData+offset, controlIdTlvData, controlIdTlvDataSize);
136	    offset += controlIdTlvDataSize;
137	    memcpy(rkeData+offset, controlDataTlvData, controlDataTlvDataSize);
138	    offset += controlDataTlvDataSize;
139	    safe_free(controlIdTlvData);
140	    safe_free(controlDataTlvData);
141	    uint8_t *rkeTlvData = (uint8_t *)encodeTlvMessage(rkeType, rkeDataLength, rkeData);
142	    safe_free(rkeData);
143	    *rkeTlvResultData = rkeTlvData;
144	    return BleKeyV3RkeRequestCreateSuccess;
145	}
