148	// auth0
149	BleKeyV3Auth0RequestCreateResult createBleKeyV3Auth0RequestWithInput(BleKeyV3Auth0Params *auth0Params, uint8_t pollingEnableSwitch, uint8_t *auth0EncodeData, size_t *auth0EncodeDataSize) {
150	    __CHECK_RET(auth0Params != NULL, BleKeyV3Auth0RequestCreateAuth0ParamsIsNull)
151	    __CHECK_RET(auth0Params->authKey != NULL, BleKeyV3Auth0RequestCreateAuth0ParamsIsNull)
152	    uint8_t *indicatorTlvData = (uint8_t *)encodeTlvMessage(BLEKeyV3AuthDataTypeIndictor, auth0Params->indicatorSize, auth0Params->indictor);
153	    __CHECK_RET(indicatorTlvData != NULL, BleKeyV3Auth0RequestCreateIndicatorIsNull)
154	    uint8_t *authFactorTlvData = NULL;
155	    BleKeyV3Auth0RequestCreateResult authFactorResult = getAuth0FactorTlvData(auth0Params->uid, auth0Params->keyId, auth0Params->keyIdSize, auth0Params->rand0, auth0Params->timeStamp,&authFactorTlvData);
156	    if (authFactorResult != BleKeyV3Auth0RequestCreateSuccess) {
157	        return authFactorResult;
158	    }
159	    uint8_t *pollingConfigTlvData = NULL;
160	    BleKeyV3Auth0RequestCreateResult pollingConfigResult = getPollingConfigTlvData(&auth0Params->pollingConfig, pollingEnableSwitch, auth0Params->deviceModel, auth0Params->deviceModelSize, auth0Params->bleName, auth0Params->bleNameSize,&pollingConfigTlvData);
161	    if (pollingConfigResult != BleKeyV3Auth0RequestCreateSuccess) {
162	        return authFactorResult;
163	    }
164	    size_t indicatorSize = getTlvTotalSize(indicatorTlvData);
165	    size_t authFactorSize = getTlvTotalSize(authFactorTlvData);
166	    size_t pollingConfigSize = getTlvTotalSize(pollingConfigTlvData);
167	
168	    size_t rawDataSize = authFactorSize + pollingConfigSize ;
169	    memcpy(auth0EncodeData, authFactorTlvData, authFactorSize);
170	    memcpy(auth0EncodeData+authFactorSize, pollingConfigTlvData, pollingConfigSize);
171	    safe_free(authFactorTlvData);
172	    safe_free(pollingConfigTlvData);
173	//    DLogTagInfo(kBLEKeyTag, @"加密前数据:%@",[NSData dataWithBytes:rawData length:authFactorSize+pollingConfigSize].hexString);
174	    unsigned int encodeDataSize = 0;
