#include "BLEKeyV3EncodeMessage.hpp"
#include "../tools/DataCovertTool.h"
#include "ble_key_apdu_parser.hpp"
#include "BLEKeyV3MsgAlgorithm.hpp"
#include <cstring>
#include <cstdlib>

using namespace SDKBleKeyV3;

BleKeyV3Auth0RequestCreateResult getAuth0FactorTlvData(uint64_t uid, const uint8_t *keyIdData,size_t keyIdSize, uint32_t r0,uint64_t timeStamp,uint8_t **authFactorTlvResultData) {
    __CHECK_RET(keyIdData != NULL && keyIdSize != 0,BleKeyV3Auth0RequestCreateKeyIdIsNull)
    uint64_t uidLittleEndian = host_int64_to_little_endian(uid);
    uint8_t *uidTlvData = (uint8_t *)encodeTlvMessage(BLEKeyV3Auth0RequestFactorTypeUid, sizeof(uint64_t), &uidLittleEndian);

    uint8_t *keyIdTlvData = (uint8_t *)encodeTlvMessage(BLEKeyV3Auth0RequestFactorTypeKid,keyIdSize,keyIdData);

    uint32_t r0LittleEndian = host_int32_to_little_endian(r0);
    uint8_t *r0TlvData = (uint8_t *)encodeTlvMessage(BLEKeyV3Auth0RequestFactorTypeRand0, sizeof(uint32_t), &r0LittleEndian);

    uint64_t timeStampLittleEndian = host_int64_to_little_endian(timeStamp);
    uint8_t *timeStampTlvData = (uint8_t *)encodeTlvMessage(BLEKeyV3Auth0RequestFactorTypeTimeStamp, sizeof(uint64_t), &timeStampLittleEndian);
    size_t uidTlvDataSize = getTlvTotalSize(uidTlvData);
    size_t keyIdTlvDataSize = getTlvTotalSize(keyIdTlvData);
    size_t r0TlvDataSize = getTlvTotalSize(r0TlvData);
    size_t timeStampTlvDataSize = getTlvTotalSize(timeStampTlvData);
    size_t authFactorLength = uidTlvDataSize + keyIdTlvDataSize + r0TlvDataSize + timeStampTlvDataSize;
    uint8_t *authFactorData = (uint8_t *)malloc(authFactorLength);
    size_t offset = 0;
    memcpy(authFactorData+offset, uidTlvData, uidTlvDataSize);
    offset += uidTlvDataSize;
    memcpy(authFactorData+offset, keyIdTlvData, keyIdTlvDataSize);
    offset += keyIdTlvDataSize;
    memcpy(authFactorData+offset, r0TlvData, r0TlvDataSize);
    offset += r0TlvDataSize;
    memcpy(authFactorData+offset, timeStampTlvData,timeStampTlvDataSize);
    offset += timeStampTlvDataSize;
    safe_free(uidTlvData);
    safe_free(keyIdTlvData);
    safe_free(r0TlvData);
    safe_free(timeStampTlvData);
    uint8_t *authFactorTlvData = (uint8_t *)encodeTlvMessage(BLEKeyV3AuthDataTypeAuth0RequestFactor, authFactorLength, authFactorData);
    safe_free(authFactorData);
    *authFactorTlvResultData =  authFactorTlvData;
    return BleKeyV3Auth0RequestCreateSuccess;
}

BleKeyV3Auth1RequestCreateResult getAuth1FactorTlvData(uint32_t r12,uint8_t *certMessageData,size_t certMessageLength,uint8_t **authFactorTlvResultData) {
    __CHECK_RET(certMessageData != NULL && certMessageLength != 0,BleKeyV3Auth1RequestCreateCertMessageIsNull)
    uint32_t r12LittleEndian = host_int32_to_little_endian(r12);
    uint8_t *r12TlvData = (uint8_t *)encodeTlvMessage(BLEKeyV3Auth1RequestFactorTypeRand12, sizeof(r12LittleEndian), &r12LittleEndian);
    uint8_t *certMessageTlvData = (uint8_t *)encodeTlvMessage(BLEKeyV3Auth1RequestFactorTypeCertMessage, certMessageLength, certMessageData);
    size_t r12TlvDataSize = getTlvTotalSize(r12TlvData);
    size_t certMessageTlvDataSize = getTlvTotalSize(certMessageTlvData);
    size_t authFactorLength = r12TlvDataSize + certMessageTlvDataSize;
    uint8_t *authFactorData = (uint8_t *)malloc(authFactorLength);
    size_t offset = 0;
    memcpy(authFactorData+offset, r12TlvData, r12TlvDataSize);
    offset += r12TlvDataSize;
    memcpy(authFactorData+offset, certMessageTlvData, getTlvTotalSize(certMessageTlvData));
    offset += certMessageTlvDataSize;
    safe_free(r12TlvData);
    safe_free(certMessageTlvData);
    uint8_t *authFactorTlvData = (uint8_t *)encodeTlvMessage(BLEKeyV3AuthDataTypeAuth1RequestFactor, authFactorLength, authFactorData);
    safe_free(authFactorData);
    *authFactorTlvResultData = authFactorTlvData;
    return BleKeyV3Auth1RequestCreateSuccess;
}

uint8_t * getPollingCustomeData(BleKeyV3PollingConfigParams *pollingConfigParams, uint8_t tag) {
    size_t pollingDataHeaderLength = sizeof(BleKeyV3PollingConfigParams) - sizeof(pollingConfigParams->selfCalibrationData);
    size_t pollingDataLength = 0;
    if (pollingConfigParams->selfCalibrationLen != 0) {
        pollingDataLength = pollingConfigParams->selfCalibrationLen;
    }
    uint8_t *pollingData = (uint8_t *)malloc(pollingDataHeaderLength+pollingDataLength);
    memcpy(pollingData, pollingConfigParams, pollingDataHeaderLength);
    if (pollingConfigParams->selfCalibrationLen != 0) {
        memcpy(pollingData+pollingDataHeaderLength, pollingConfigParams->selfCalibrationData, pollingConfigParams->selfCalibrationLen);
    }
    uint8_t *pollingTlvData = (uint8_t *)encodeTlvMessage(tag, pollingDataHeaderLength+pollingDataLength, pollingData);
    safe_free(pollingData);
    return pollingTlvData;
}

BleKeyV3Auth0RequestCreateResult getPollingConfigTlvData(BleKeyV3PollingConfigParams *pollingConfigParams, uint8_t pollingEnableSwitch, uint8_t *deviceModelData, size_t deviceModelLen, uint8_t *bleNameData, size_t bleNameLen, uint8_t **pollingConfigTlvResultData) {
    __CHECK_RET(deviceModelData != NULL && deviceModelLen != 0,BleKeyV3Auth0RequestCreateDeviceModelIsNull)
    __CHECK_RET(bleNameData != NULL && bleNameLen != 0,BleKeyV3Auth0RequestCreateDeviceNameIsNull)
    uint8_t *pollingTlvData = getPollingCustomeData(pollingConfigParams, BLEKeyV3Auth0RequestPollingConfigTypeCustomeRssi);
    uint8_t *deviceModelTlvData = (uint8_t *)encodeTlvMessage(BLEKeyV3Auth0RequestPollingConfigTypeDeviceModel, deviceModelLen, deviceModelData);
    uint8_t *bleNameTlvData = (uint8_t *)encodeTlvMessage(BLEKeyV3Auth0RequestPollingConfigTypeBleName, bleNameLen, bleNameData);
    uint8_t *pollingEnableConfigTlvData = (uint8_t *)encodeTlvMessage(BLEKeyV3Auth0RequestPollingConfigEnableSwitch, sizeof(pollingEnableSwitch), &pollingEnableSwitch);

    size_t pollingTlvDataSize = getTlvTotalSize(pollingTlvData);
    size_t deviceModelTlvDataSize = getTlvTotalSize(deviceModelTlvData);
    size_t bleNameTlvDataSize = getTlvTotalSize(bleNameTlvData);
    size_t pollingEnableConfigTlvDataSize = getTlvTotalSize(pollingEnableConfigTlvData);
    uint8_t pollingConfigLenth = pollingTlvDataSize + deviceModelTlvDataSize + bleNameTlvDataSize + pollingEnableConfigTlvDataSize;
    uint8_t *pollingConfigData = (uint8_t *)malloc(pollingConfigLenth);
    uint8_t offset = 0;
    memcpy(pollingConfigData+offset, pollingTlvData, pollingTlvDataSize);
    offset += pollingTlvDataSize;
    memcpy(pollingConfigData+offset, deviceModelTlvData, deviceModelTlvDataSize);
    offset += deviceModelTlvDataSize;
    memcpy(pollingConfigData+offset, bleNameTlvData, bleNameTlvDataSize);
    offset += bleNameTlvDataSize;
    memcpy(pollingConfigData+offset, pollingEnableConfigTlvData, pollingEnableConfigTlvDataSize);
    offset += pollingEnableConfigTlvDataSize;

    safe_free(pollingTlvData);
    safe_free(deviceModelTlvData);
    safe_free(bleNameTlvData);
    safe_free(pollingEnableConfigTlvData);
    uint8_t *pollingConfigTlvData = (uint8_t *)encodeTlvMessage(BLEKeyV3AuthDataTypePollingConfig, pollingConfigLenth, pollingConfigData);
    safe_free(pollingConfigData);
    *pollingConfigTlvResultData = pollingConfigTlvData;
    return BleKeyV3Auth0RequestCreateSuccess;
}

BleKeyV3RkeRequestCreateResult getRKEDataWithRkeType(BLEKeyV3RKERequestType rkeType,uint8_t controlId,uint8_t *controlData,size_t controlDataSize,uint8_t **rkeTlvResultData) {
    __CHECK_RET(controlData != NULL && controlDataSize != 0,BleKeyV3RkeRequestCreateRkeDataIsNull)
    uint8_t *controlIdTlvData = (uint8_t *)encodeTlvMessage(BLEKeyV3RKEDataTypeControlId, sizeof(uint8_t), &controlId);
    uint8_t *controlDataTlvData = (uint8_t *)encodeTlvMessage(BLEKeyV3RKEDataTypeControlData, controlDataSize, controlData);
    size_t controlIdTlvDataSize = getTlvTotalSize(controlIdTlvData);
    size_t controlDataTlvDataSize = getTlvTotalSize(controlDataTlvData);
    size_t rkeDataLength = controlIdTlvDataSize +controlDataTlvDataSize;
    uint8_t *rkeData = (uint8_t *)malloc(rkeDataLength);
    uint8_t offset = 0;
    memcpy(rkeData+offset, controlIdTlvData, controlIdTlvDataSize);
    offset += controlIdTlvDataSize;
    memcpy(rkeData+offset, controlDataTlvData, controlDataTlvDataSize);
    offset += controlDataTlvDataSize;
    safe_free(controlIdTlvData);
    safe_free(controlDataTlvData);
    uint8_t *rkeTlvData = (uint8_t *)encodeTlvMessage(rkeType, rkeDataLength, rkeData);
    safe_free(rkeData);
    *rkeTlvResultData = rkeTlvData;
    return BleKeyV3RkeRequestCreateSuccess;
}


// auth0
BleKeyV3Auth0RequestCreateResult createBleKeyV3Auth0RequestWithInput(BleKeyV3Auth0Params *auth0Params, uint8_t pollingEnableSwitch, uint8_t *auth0EncodeData, size_t *auth0EncodeDataSize) {
    __CHECK_RET(auth0Params != NULL, BleKeyV3Auth0RequestCreateAuth0ParamsIsNull)
    __CHECK_RET(auth0Params->authKey != NULL, BleKeyV3Auth0RequestCreateAuth0ParamsIsNull)
    uint8_t *indicatorTlvData = (uint8_t *)encodeTlvMessage(BLEKeyV3AuthDataTypeIndictor, auth0Params->indicatorSize, auth0Params->indictor);
    __CHECK_RET(indicatorTlvData != NULL, BleKeyV3Auth0RequestCreateIndicatorIsNull)
    uint8_t *authFactorTlvData = NULL;
    BleKeyV3Auth0RequestCreateResult authFactorResult = getAuth0FactorTlvData(auth0Params->uid, auth0Params->keyId, auth0Params->keyIdSize, auth0Params->rand0, auth0Params->timeStamp,&authFactorTlvData);
    if (authFactorResult != BleKeyV3Auth0RequestCreateSuccess) {
        return authFactorResult;
    }
    uint8_t *pollingConfigTlvData = NULL;
    BleKeyV3Auth0RequestCreateResult pollingConfigResult = getPollingConfigTlvData(&auth0Params->pollingConfig, pollingEnableSwitch, auth0Params->deviceModel, auth0Params->deviceModelSize, auth0Params->bleName, auth0Params->bleNameSize,&pollingConfigTlvData);
    if (pollingConfigResult != BleKeyV3Auth0RequestCreateSuccess) {
        return authFactorResult;
    }
    size_t indicatorSize = getTlvTotalSize(indicatorTlvData);
    size_t authFactorSize = getTlvTotalSize(authFactorTlvData);
    size_t pollingConfigSize = getTlvTotalSize(pollingConfigTlvData);

    size_t rawDataSize = authFactorSize + pollingConfigSize ;
    memcpy(auth0EncodeData, authFactorTlvData, authFactorSize);
    memcpy(auth0EncodeData+authFactorSize, pollingConfigTlvData, pollingConfigSize);
    safe_free(authFactorTlvData);
    safe_free(pollingConfigTlvData);
//    DLogTagInfo(kBLEKeyTag, @"加密前数据:%@",[NSData dataWithBytes:rawData length:authFactorSize+pollingConfigSize].hexString);
    unsigned int encodeDataSize = 0;
    unsigned char iv_copy[16];
    memcpy(iv_copy, bleKeyV3IvData, 16);
    unsigned char *key = (unsigned char *)calloc(1, auth0Params->authKeySize);
    memcpy(key, auth0Params->authKey, auth0Params->authKeySize);
    unsigned char *encodedData = aes_256_cbc_encrypt((unsigned char *)auth0EncodeData, rawDataSize, key, (unsigned char *)iv_copy,&encodeDataSize);
    safe_free(key);
    size_t auth0DataLength = encodeDataSize + indicatorSize;
    memcpy(auth0EncodeData, indicatorTlvData, indicatorSize);
    memcpy(auth0EncodeData+indicatorSize, encodedData, encodeDataSize);
    safe_free(indicatorTlvData);
    uint16_t checkSum = calc_crc16_ccitt(auth0EncodeData,auth0DataLength);
    uint16_t checkSumLittleEndian = host_int16_to_little_endian(checkSum);
    BLEKeyV3Message v3Message;
    v3Message.msgId = BLEKeyV3MessageTypeAuth0;
    v3Message.msgLength = auth0DataLength;
    v3Message.messageData = (uint8_t *)malloc(auth0DataLength);
    memcpy(v3Message.messageData, auth0EncodeData, auth0DataLength);
    v3Message.checkSum = checkSumLittleEndian;
    copyBleV3MessageRawData(&v3Message,auth0EncodeData);
    *auth0EncodeDataSize = sizeOfBLEKeyV3Message(&v3Message);
    return BleKeyV3Auth0RequestCreateSuccess;
}


// auth1
BleKeyV3Auth1RequestCreateResult createBleKeyV3Auth1RequestWithInput(BleKeyV3Auth1Params *auth1Params,uint8_t *auth1EncodeData,size_t *auth1EncodeDataSize) {
    __CHECK_RET(auth1Params != NULL, BleKeyV3Auth1RequestCreateAuth1ParamsIsNull)
    __CHECK_RET(auth1Params->sessionKey != NULL && auth1Params->sessionKeySize != 0, BleKeyV3Auth1RequestCreateSessionKeyIsNull)
    uint8_t *authFactorTlvData = NULL;
    BleKeyV3Auth1RequestCreateResult authFactorResult = getAuth1FactorTlvData(auth1Params->rand12, auth1Params->certMessage, auth1Params->certMessageSize,&authFactorTlvData);
    if (authFactorResult != BleKeyV3Auth1RequestCreateSuccess) {
        return authFactorResult;
    }
    size_t authFactorSize = getTlvTotalSize(authFactorTlvData);
    uint32_t xorResultSize = 0;
    uint8_t *sessionXorResult = getXorResult(&xorResultSize, authFactorTlvData, authFactorSize, auth1Params->sessionKey, auth1Params->sessionKeySize);
    safe_free(authFactorTlvData);
    uint16_t checkSum = calc_crc16_ccitt(sessionXorResult,xorResultSize);
    uint16_t checkSumLittleEndian = host_int16_to_little_endian(checkSum);
    BLEKeyV3Message v3Message;
    v3Message.msgId = BLEKeyV3MessageTypeAuth1;
    v3Message.msgLength = xorResultSize;
    v3Message.messageData = (uint8_t *)malloc(xorResultSize);
    memcpy(v3Message.messageData, sessionXorResult, xorResultSize);
    safe_free(sessionXorResult);
    v3Message.checkSum = checkSumLittleEndian;
    copyBleV3MessageRawData(&v3Message,auth1EncodeData);
    *auth1EncodeDataSize = sizeOfBLEKeyV3Message(&v3Message);
    return BleKeyV3Auth1RequestCreateSuccess;
}


// rke
BleKeyV3RkeRequestCreateResult createBleKeyV3RkeRequestWithInput(BleKeyV3RkeParams *rkeParams,int isSecure,uint8_t *rkeEncodeData,size_t *rkeEncodeDataSize) {
    __CHECK_RET(rkeParams != NULL, BleKeyV3RkeRequestCreateRkeParamsIsNull)
    __CHECK_RET(rkeParams->rkeData != NULL && rkeParams->rkeDataSize != 0, BleKeyV3RkeRequestCreateRkeDataIsNull)
    uint8_t *rkeTlvData = NULL;
    BleKeyV3RkeRequestCreateResult rkeDataResult = getRKEDataWithRkeType(rkeParams->rkeType, rkeParams->rkeId, rkeParams->rkeData, rkeParams->rkeDataSize,&rkeTlvData);
    if (rkeDataResult != BleKeyV3RkeRequestCreateSuccess) {
        return rkeDataResult;
    }
    size_t rkeTlvSize = getTlvTotalSize(rkeTlvData);
    if (isSecure) {
        __CHECK_RET(rkeParams->sessionKey != NULL && rkeParams->sessionKeySize != 0, BleKeyV3RkeRequestCreateSessionKeyIsNull)
        __CHECK_RET(rkeParams->hmacKey != NULL && rkeParams->hmacKeySize != 0, BleKeyV3RkeRequestCreateHmacKeyIsNull)
        size_t xorResultSize = 0;
        uint8_t * sessionXorResult = getXorResult((unsigned int *)&xorResultSize, rkeTlvData, rkeTlvSize, rkeParams->sessionKey, rkeParams->sessionKeySize);
        size_t hmacDataSize = 0;
        uint8_t *hmacData = hmac_sha256(rkeParams->hmacKey, rkeParams->hmacKeySize, rkeTlvData, rkeTlvSize, (unsigned int *)&hmacDataSize);
        safe_free(rkeTlvData);
        size_t authedDataLength = xorResultSize + hmacDataSize;
        memcpy(rkeEncodeData, sessionXorResult, xorResultSize);
        memcpy(rkeEncodeData+xorResultSize, hmacData, hmacDataSize);
        safe_free(sessionXorResult);
        safe_free(hmacData);
        uint16_t checkSum = calc_crc16_ccitt(rkeEncodeData,authedDataLength);
        uint16_t checkSumLittleEndian = host_int16_to_little_endian(checkSum);
        BLEKeyV3Message v3Message;
