BleKeyV3NotifyRequestCreateResult createCombinedNotifyData(uint8_t *combinedData, int combinedDataSize, int isSecure,uint8_t *sessionKey,int sessionKeySize, uint8_t *notifyEncodeData,size_t *notifyEncodeDataSize) {
    __CHECK_RET(combinedData != NULL && combinedDataSize != 0, BleKeyV3NotifyRequestCreateNotifyParamsIsNull)
    if (isSecure) {
        size_t xorResultSize = 0;
        uint8_t * sessionXorResult = getXorResult((unsigned int *)&xorResultSize, combinedData, combinedDataSize, sessionKey, sessionKeySize);
        uint16_t checkSum = calc_crc16_ccitt(sessionXorResult,xorResultSize);
        uint16_t checkSumLittleEndian = host_int16_to_little_endian(checkSum);
        BLEKeyV3Message v3Message;
        v3Message.msgId = BLEKeyV3MessageTypeNotification;
        v3Message.msgLength = xorResultSize;
        v3Message.messageData = (uint8_t *)malloc(xorResultSize);
        memcpy(v3Message.messageData, sessionXorResult, xorResultSize);
        v3Message.checkSum = checkSumLittleEndian;
        copyBleV3MessageRawData(&v3Message,notifyEncodeData);
        *notifyEncodeDataSize = sizeOfBLEKeyV3Message(&v3Message);
        return BleKeyV3NotifyRequestCreateSuccess;
    } else {
        uint16_t checkSum = calc_crc16_ccitt(combinedData, combinedDataSize);
        uint16_t checkSumLittleEndian = host_int16_to_little_endian(checkSum);
        BLEKeyV3Message v3Message;
        v3Message.msgId = BLEKeyV3MessageTypeNotification;
        v3Message.msgLength = combinedDataSize;
        v3Message.messageData = (uint8_t *)malloc(combinedDataSize);
        memcpy(v3Message.messageData, combinedData, combinedDataSize);
        v3Message.checkSum = checkSumLittleEndian;
        copyBleV3MessageRawData(&v3Message, notifyEncodeData);
        *notifyEncodeDataSize = sizeOfBLEKeyV3Message(&v3Message);
        return BleKeyV3NotifyRequestCreateSuccess;
    }
}

