30	uint8_t covertTrunkState(uint8_t originValue) {
31	    if (3 == originValue) {
32	        return 1;
33	    } else if (originValue == 0) {
34	        return 0xFF;
35	    } else if (originValue == 1) {
36	        return 0;
37	    } else if (originValue == 2) {
38	        return 3;
39	    } else if (originValue == 4) {
40	        return 2;
41	    } else {
42	        return originValue;
43	    }
44	}
