46	uint8_t covertExtDoorState(uint8_t originValue) {
47	    if (originValue == 1) {
48	        return CarScissorsDoorStateClose;
49	    } else if (originValue == 2) {
50	        return CarScissorsDoorStateOpening;
51	    } else if (originValue == 3) {
52	        return CarScissorsDoorStateClosing;
53	    } else if (originValue == 4) {
54	        return CarScissorsDoorStateStop;
55	    } else if (originValue == 5) {
56	        return CarScissorsDoorStateOpen;
57	    } else {
58	        return CarScissorsDoorStateNotAvailable;
59	    }
60	}
