88	void BleKeyV3DataParser::buildSelfCalibrationMessage(SelfCalibrationMessage *selfCalibrationData) {
89	    kCarEventStart(selfCalibration, selfCalibrationMessageHeader)
90	    kAddUInt8ItemToJson(selfCalibration, "result", selfCalibrationData->result);
91	    kAddUInt8ItemToJson(selfCalibration, "resultLen", selfCalibrationData->resultLen);
92	    if (selfCalibrationData->resultLen != 0) {
93	
94	        uint8_t length = sizeof(selfCalibrationData->direction) + sizeof(selfCalibrationData->resultLen) + selfCalibrationData->resultLen;
95	        uint8_t *uploadData = (uint8_t *)malloc(length);
96	                
97	        memcpy(uploadData, &selfCalibrationData->direction, sizeof(selfCalibrationData->direction));
98	        memcpy(uploadData + sizeof(selfCalibrationData->direction), &selfCalibrationData->resultLen, sizeof(selfCalibrationData->resultLen));
99	        memcpy(uploadData + sizeof(selfCalibrationData->direction) + sizeof(selfCalibrationData->resultLen), selfCalibrationData->resultData, selfCalibrationData->resultLen);
100	        
101	        char *hexStr = (char *)calloc(1, length * 2 + 1);
102	        bytesToHexString(uploadData, length, hexStr);
103	        cJSON_AddStringToObject(selfCalibration, "resultData", hexStr);
104	        safe_free(hexStr);
105	        safe_free(uploadData);
106	        safe_free(selfCalibrationData->resultData);
107	    }
108	    kAddUInt8ItemToJson(selfCalibration, "direction", selfCalibrationData->direction);
109	    kAddUInt8ItemToJson(selfCalibration, "distance", selfCalibrationData->distance);
110	    kAddUInt32ItemToJson(selfCalibration, "uid", selfCalibrationData->uid);
111	    if (selfCalibrationData->deviceModel.len != 0) {
112	        char * deviceModel = (char *)calloc(1, selfCalibrationData->deviceModel.len + 1);
113	        memcpy(deviceModel, selfCalibrationData->deviceModel.value, selfCalibrationData->deviceModel.len);
114	        cJSON_AddStringToObject(selfCalibration, "deviceModel", deviceModel);
115	        safe_free(deviceModel);
116	        safe_free(selfCalibrationData->deviceModel.value);
117	    }
118	    kCarEventEnd(selfCalibration, this->resultArray);
