159	void BleKeyV3DataParser::parseAuth0Response(BleKeyV3OutputMessage *outputMessage) {
160	    BleKeyV3ByteBaseMessage messageData = outputMessage->messageData;
161	    BleKeyV3Auth0Response *auth0Response = (BleKeyV3Auth0Response *)messageData.value;
162	    
163	    Auth0ResponseMessage auth0ResponseMessage;
164	    if (auth0Response->rand01.len > sizeof(auth0ResponseMessage.rand01) || auth0Response->rand1.len > sizeof(auth0ResponseMessage.rand1)) {
165	        XP_LOG_INFO("BleKeyV3", "protocol len error,need bigger Auth0ResponseMessage");
166	    } else {
167	        auth0ResponseMessage.rand01 = auth0Response->rand01.value;
168	        auth0ResponseMessage.rand1 = auth0Response->rand1.value;
169	    }
170	    buildAuth0ResponseMessage(&auth0ResponseMessage);
171	}
