173	void BleKeyV3DataParser::parseCommonCarState(BleKeyV3OutputMessage *outputMessage) {
174	    BleKeyV3ByteBaseMessage messageData = outputMessage->messageData;
175	    BleKeyV3CarStateD0 *commonCarStates = (BleKeyV3CarStateD0 *)messageData.value;
176	    
177	    DoorMessage doorMessage;
178	    doorMessage.driver_door_lock_st = commonCarStates->lockState;
179	    doorMessage.driver_door_ajar_st = commonCarStates->leftFrontDoorState;
180	    doorMessage.passenger_door_ajar_st = commonCarStates->rightFrontDoorState;
181	    doorMessage.rear_left_door_ajar_st = commonCarStates->leftBackDoorState;
182	    doorMessage.rear_right_door_ajar_st = commonCarStates->rightBackDoorState;
183	    doorMessage.trunk_ajar_st = covertTrunkState(commonCarStates->trunckState);
184	    doorMessage.bonnet_ajar_st = commonCarStates->bonnetAjarState;
185	    doorMessage.temp_lock_st = commonCarStates->tempeoryLockState;
186	    doorMessage.trunk_ajar_st_new = commonCarStates->trunckActionState;
187	    doorMessage.left_slide_door_status = commonCarStates->leftSlideState;
188	    doorMessage.left_slide_door_position = commonCarStates->leftSlideOpenDegree;
189	    doorMessage.right_slide_door_status = commonCarStates->rightSlideState;
190	    doorMessage.right_slide_door_position = commonCarStates->rightSlideOpenDegree;
191	    doorMessage.front_left_power_door = commonCarStates->leftFrontElecDoorState;
192	    doorMessage.rear_left_power_door = commonCarStates->leftBackElecDoorState;
193	    doorMessage.front_right_power_door = commonCarStates->rightFrontElecDoorState;
194	    doorMessage.rear_right_power_door = commonCarStates->rightBackElecDoorState;
195	    doorMessage.super_lock_status = commonCarStates->superLockState;
196	    buildDoorMessage(&doorMessage);
197	    
198	    WindowMessage windowMessage;
199	    windowMessage.front_left_window_position = convertWindowState(commonCarStates->leftFrontWindowDegree);
200	    windowMessage.front_right_window_position = convertWindowState(commonCarStates->rightFrontWindowDegree);
201	    windowMessage.rear_left_window_position = convertWindowState(commonCarStates->leftBackWindowDegree);
202	    windowMessage.rear_right_window_position = convertWindowState(commonCarStates->rightBackWindowDegree);
203	    buildWindowMessage(&windowMessage);
204	    
205	    ExtDoorMessage extDoorMessage;
206	    extDoorMessage.mainDoorState = covertExtDoorState(commonCarStates->mainExtDoorState);
207	    extDoorMessage.subDoorState = covertExtDoorState(commonCarStates->subExtDoorState);
208	    buildExtDoorMessage(&extDoorMessage);
209	    
210	    TrailerHookStateMessage trailerHookMessage;
211	    trailerHookMessage.hook_status = commonCarStates->trailerHookState;
212	    trailerHookMessage.hook_machine_status = commonCarStates->trailerHookMachineState;
213	    trailerHookMessage.hook_system_monitor = commonCarStates->trailerHookSystemState;
214	    buildTrailerHookStateMessage(&trailerHookMessage);
215	    
216	    WireControlStateMessage wireControlMessage;
217	    wireControlMessage.wire_control_mode = commonCarStates->wireControlModeState;
218	    buildWireControlStateMessage(&wireControlMessage);
219	
220	}
