371	cJSON * BleKeyV3DataParser::parse(const uint8_t* data, size_t dataSize,uint8_t *sessionKey,size_t sessionKeySize,uint8_t *authKey,size_t authKeySize,int isEncrypted) {
372	    // 应急钥匙报文判断
373	    if (isRescueBleKeyV3Message(data, dataSize)) {
374	        return parseRescueBleKeyV3Message(data, dataSize, sessionKey, sessionKeySize, authKey, authKeySize, isEncrypted);
375	    }
376	    
377	    BleKeyV3CanMessageParams canMessageParams;
378	    canMessageParams.isEncrypted = (uint8_t)isEncrypted;
379	    canMessageParams.canMessage.len = dataSize;
380	    canMessageParams.canMessage.value = (uint8_t *)malloc(dataSize);
381	    memcpy(canMessageParams.canMessage.value, data, dataSize);
382	    if (isEncrypted) {
383	        canMessageParams.authKeyMessage.len = authKeySize;
384	        canMessageParams.authKeyMessage.value = (uint8_t *)malloc(authKeySize);
385	        memcpy(canMessageParams.authKeyMessage.value, authKey, authKeySize);
386	        canMessageParams.sessionKeyMessage.len = sessionKeySize;
387	        canMessageParams.sessionKeyMessage.value = (uint8_t *)malloc(sessionKeySize);
388	        memcpy(canMessageParams.sessionKeyMessage.value, sessionKey, sessionKeySize);
389	    }
390	    BleKeyV3OutputMessageParams outputMessageParams;
391	    decodeBleKeyV3CanMessage(&canMessageParams,&outputMessageParams);
392	    if (outputMessageParams.result != BleKeyV3DecodeV3CanMessageSuccess || outputMessageParams.outputSize <= 0) {
393	        return NULL;
394	    }
395	    for (int i = 0; i<outputMessageParams.outputSize; i++) {
396	        BleKeyV3OutputMessage &outputMessage = outputMessageParams.outputMessages[i];
397	        if (outputMessage.messageType == BleKeyV3OutputMessageTypeCommonStatus ||
398	            outputMessage.messageType == BleKeyV3OutputMessageTypeCommonErrorCode ||
399	            outputMessage.messageType == BleKeyV3OutputMessageTypeCommonErrorReason) {
400	            this->specialMessages.push_back(outputMessage);
401	        } else {
402	            this->parseSingleMessage(&outputMessage);
403	        }
404	    }
405	    this->parseSpecialMessage();
406	    
407	    if (canMessageParams.canMessage.value != NULL) {
408	        free(canMessageParams.canMessage.value);
409	        canMessageParams.canMessage.value = NULL;
410	    }
411	    if (isEncrypted) {
412	        if (canMessageParams.sessionKeyMessage.value != NULL) {
413	            free(canMessageParams.sessionKeyMessage.value);
414	            canMessageParams.sessionKeyMessage.value = NULL;
415	        }
416	        if (canMessageParams.authKeyMessage.value != NULL) {
417	            free(canMessageParams.authKeyMessage.value);
418	            canMessageParams.authKeyMessage.value = NULL;
419	        }
420	    }
421	    freeBleV3OutputMessages(&outputMessageParams);
422	    
423	    cJSON *result = parserEnd();
424	    return result;
425	}
