427	void BleKeyV3DataParser::parseSpecialMessage() {
428	    if (this->specialMessages.size() == 0) {
429	        return;
430	    }
431	    CommonResponseMessage commonResponseMessage;
432	    for (const auto &outputMessage : this->specialMessages) {
433	        switch (outputMessage.messageType) {
434	            case BleKeyV3OutputMessageTypeCommonStatus:
435	                memcpy(&commonResponseMessage.status, outputMessage.messageData.value, sizeof(commonResponseMessage.status));
436	                break;
437	            case BleKeyV3OutputMessageTypeCommonErrorCode:
438	                memcpy(&commonResponseMessage.errorCode, outputMessage.messageData.value, sizeof(commonResponseMessage.errorCode));
439	                break;
440	            case BleKeyV3OutputMessageTypeCommonErrorReason:
441	                commonResponseMessage.errorReason.len = outputMessage.messageData.len;
442	                if (outputMessage.messageData.len > 0) {
443	                    commonResponseMessage.errorReason.value = (uint8_t *)calloc(1, commonResponseMessage.errorReason.len + 1);
444	                    memcpy(commonResponseMessage.errorReason.value, outputMessage.messageData.value, commonResponseMessage.errorReason.len);
445	                }
446	                break;
447	                
448	            default:
449	                break;
450	        }
451	    }
452	    buildCommonResponseMessage(&commonResponseMessage);
453	}
