455	void BleKeyV3DataParser::parseSingleMessage(BleKeyV3OutputMessage *outputMessage) {
456	    switch (outputMessage->messageType) {
457	        case BleKeyV3OutputMessageTypeAuth0Response:
458	        {
459	            parseAuth0Response(outputMessage);
460	        }
461	            break;
462	        case BleKeyV3OutputMessageTypeCommonCarState:
463	        {
464	            parseCommonCarState(outputMessage);
465	        }
466	            break;
467	        case BleKeyV3OutputMessageTypeChargeState:
468	        {
469	            parseChargeState(outputMessage);
