475	        }
476	            break;
477	        case BleKeyV3OutputMessageTypeNumeric:
478	        {
479	            parseNumericMessage(outputMessage);
480	        }
481	            break;
482	        case BleKeyV3OutputMessageTypeSelfCalibration:
483	        {
484	            parseSelfCalibrationMessage(outputMessage);
485	        }
486	            break;
487	        case BleKeyV3OutputMessageTypeRssiCollect:
488	        {
