void BleKeyV3DataParser::parseAuth0Response(BleKeyV3OutputMessage *outputMessage) {
    BleKeyV3ByteBaseMessage messageData = outputMessage->messageData;
    BleKeyV3Auth0Response *auth0Response = (BleKeyV3Auth0Response *)messageData.value;

    Auth0ResponseMessage auth0ResponseMessage;
    if (auth0Response->rand01.len > sizeof(auth0ResponseMessage.rand01) || auth0Response->rand1.len > sizeof(auth0ResponseMessage.rand1)) {
        XP_LOG_INFO("BleKeyV3", "protocol len error,need bigger Auth0ResponseMessage");
    } else {
        auth0ResponseMessage.rand01 = auth0Response->rand01.value;
        auth0ResponseMessage.rand1 = auth0Response->rand1.value;
    }
    buildAuth0ResponseMessage(&auth0ResponseMessage);
}

void BleKeyV3DataParser::parseCommonCarState(BleKeyV3OutputMessage *outputMessage) {
    BleKeyV3ByteBaseMessage messageData = outputMessage->messageData;
    BleKeyV3CarStateD0 *commonCarStates = (BleKeyV3CarStateD0 *)messageData.value;

    DoorMessage doorMessage;
    doorMessage.driver_door_lock_st = commonCarStates->lockState;
    doorMessage.driver_door_ajar_st = commonCarStates->leftFrontDoorState;
    doorMessage.passenger_door_ajar_st = commonCarStates->rightFrontDoorState;
    doorMessage.rear_left_door_ajar_st = commonCarStates->leftBackDoorState;
    doorMessage.rear_right_door_ajar_st = commonCarStates->rightBackDoorState;
    doorMessage.trunk_ajar_st = covertTrunkState(commonCarStates->trunckState);
    doorMessage.bonnet_ajar_st = commonCarStates->bonnetAjarState;
    doorMessage.temp_lock_st = commonCarStates->tempeoryLockState;
    doorMessage.trunk_ajar_st_new = commonCarStates->trunckActionState;
    doorMessage.left_slide_door_status = commonCarStates->leftSlideState;
    doorMessage.left_slide_door_position = commonCarStates->leftSlideOpenDegree;
    doorMessage.right_slide_door_status = commonCarStates->rightSlideState;
    doorMessage.right_slide_door_position = commonCarStates->rightSlideOpenDegree;
    doorMessage.front_left_power_door = commonCarStates->leftFrontElecDoorState;
    doorMessage.rear_left_power_door = commonCarStates->leftBackElecDoorState;
    doorMessage.front_right_power_door = commonCarStates->rightFrontElecDoorState;
    doorMessage.rear_right_power_door = commonCarStates->rightBackElecDoorState;
    doorMessage.super_lock_status = commonCarStates->superLockState;
    buildDoorMessage(&doorMessage);

    WindowMessage windowMessage;
    windowMessage.front_left_window_position = convertWindowState(commonCarStates->leftFrontWindowDegree);
    windowMessage.front_right_window_position = convertWindowState(commonCarStates->rightFrontWindowDegree);
    windowMessage.rear_left_window_position = convertWindowState(commonCarStates->leftBackWindowDegree);
    windowMessage.rear_right_window_position = convertWindowState(commonCarStates->rightBackWindowDegree);
    buildWindowMessage(&windowMessage);

    ExtDoorMessage extDoorMessage;
    extDoorMessage.mainDoorState = covertExtDoorState(commonCarStates->mainExtDoorState);
    extDoorMessage.subDoorState = covertExtDoorState(commonCarStates->subExtDoorState);
    buildExtDoorMessage(&extDoorMessage);

    TrailerHookStateMessage trailerHookMessage;
    trailerHookMessage.hook_status = commonCarStates->trailerHookState;
    trailerHookMessage.hook_machine_status = commonCarStates->trailerHookMachineState;
    trailerHookMessage.hook_system_monitor = commonCarStates->trailerHookSystemState;
    buildTrailerHookStateMessage(&trailerHookMessage);

    WireControlStateMessage wireControlMessage;
    wireControlMessage.wire_control_mode = commonCarStates->wireControlModeState;
    buildWireControlStateMessage(&wireControlMessage);

}

void BleKeyV3DataParser::parseBleXpuParkingState(BleKeyV3OutputMessage *outputMessage) {
    BleKeyV3ByteBaseMessage messageData = outputMessage->messageData;
    BleKeyV3CarStateD2 *parkingV3Message = (BleKeyV3CarStateD2 *)messageData.value;

    ParkingMessage parkingEventMessage;
    parkingEventMessage.parkingState = parkingV3Message->parkingState;
    parkingEventMessage.speed = parkingV3Message->parkingSpeed;
    parkingEventMessage.parkingExpType = parkingV3Message->parkingExceptionReason;
    parkingEventMessage.gear = parkingV3Message->parkingGearVaule;
    parkingEventMessage.parkingAnimate = parkingV3Message->parkingAnimation;
    parkingEventMessage.parkingProcess = parkingV3Message->parkingDegree;

    parkingEventMessage.leaveParkState = parkingV3Message->parkingLeaveParkingState;
    parkingEventMessage.welcomeParkOutState = parkingV3Message->parkingWelcomeState;
    parkingEventMessage.parkOutAvailableDirection = parkingV3Message->parkingOutDirection;
    parkingEventMessage.parkOutCurrentDirection = parkingV3Message->parkingOutCurrentDirection;
    parkingEventMessage.parkOutDirectionIfOk = parkingV3Message->parkingChooseDirectionIsAvailable;
    parkingEventMessage.parkOutRecommendDirection = parkingV3Message->parkingOutRecommedDiretion;
    parkingEventMessage.parkOutState = parkingV3Message->parkingOutState;
    parkingEventMessage.parkInState = parkingV3Message->parkingInState;
    parkingEventMessage.parkingCollisionStatus = parkingV3Message->parkingCollisionStatus;
    parkingEventMessage.smartPKOutTips = parkingV3Message->smartPKOutTips;

    parkingEventMessage.parkingRSLAreaLevel = parkingV3Message->parkingRSLAreaLevel; // 右侧面前区域水平
    parkingEventMessage.parkingRSRAreaLevel = parkingV3Message->parkingRSRAreaLevel; // 右侧侧面区域水平
    parkingEventMessage.parkingROLAreaLevel = parkingV3Message->parkingROLAreaLevel; // 右侧后面区域水平
    parkingEventMessage.parkingRCLAreaLevel = parkingV3Message->parkingRCLAreaLevel; // 右侧车道区域水平
    parkingEventMessage.parkingRCRAreaLevel = parkingV3Message->parkingRCRAreaLevel; // 右侧车道区域水平
    parkingEventMessage.parkingRORAreaLevel = parkingV3Message->parkingRORAreaLevel; // 右侧后面区域水平
    parkingEventMessage.parkingFSLAreaLevel = parkingV3Message->parkingFSLAreaLevel; // 左侧面前区域水平
    parkingEventMessage.parkingFSRAreaLevel = parkingV3Message->parkingFSRAreaLevel; // 左侧侧面区域水平
    parkingEventMessage.parkingFOLAreaLevel = parkingV3Message->parkingFOLAreaLevel; // 左侧后面区域水平
    parkingEventMessage.parkingFCLAreaLevel = parkingV3Message->parkingFCLAreaLevel; // 左侧车道区域水平
    parkingEventMessage.parkingFCRAreaLevel = parkingV3Message->parkingFCRAreaLevel; // 右侧车道区域水平
    parkingEventMessage.parkingFORAreaLevel = parkingV3Message->parkingFORAreaLevel; // 右侧车道区域水平

    buildParkingEventMessage(&parkingEventMessage);

    ParkingMessage parkingStateMessage;
    parkingStateMessage.gear = parkingV3Message->parkingGearVaule;
    parkingStateMessage.parkingAnimate = parkingV3Message->parkingAnimation;
    buildParkingStateMessage(&parkingStateMessage);
}

void BleKeyV3DataParser::parseChargeState(BleKeyV3OutputMessage *outputMessage) {
    BleKeyV3ByteBaseMessage messageData = outputMessage->messageData;
    BleKeyV3CarStateD1 *chargeMessage = (BleKeyV3CarStateD1 *)messageData.value;

    ChargePortMessage chargePortMessage;
    chargePortMessage.slow_charge_port_status = chargeMessage->chargePortState;
    chargePortMessage.charge_gun_lock_status = chargeMessage->chargeGunLockState;
    buildChargePortMessage(&chargePortMessage);

    ChargeExtensionMessage chargeExtensionMessage;
    chargeExtensionMessage.chargePortState = chargeMessage->chargePortState;
    chargeExtensionMessage.chargePortAction = chargeMessage->chargePortAction;
    chargeExtensionMessage.powerBatteryState = chargeMessage->powerBatteryState;
    chargeExtensionMessage.chargePortInsertState = chargeMessage->chargePortInsertState;
    chargeExtensionMessage.reserveChargeState = chargeMessage->reserveChargeState;
    buildChargeExtensionMessage(&chargeExtensionMessage);
}

void BleKeyV3DataParser::parseSelfCalibrationMessage(BleKeyV3OutputMessage *outputMessage) {
    BleKeyV3ByteBaseMessage messageData = outputMessage->messageData;
    BleKeyV3CarStateD4 *d4Message = (BleKeyV3CarStateD4 *)messageData.value;

    SelfCalibrationMessage selfCalibrationMessage;
    selfCalibrationMessage.result = d4Message->result;
    selfCalibrationMessage.direction = d4Message->direction;
    selfCalibrationMessage.distance = d4Message->distance;
    selfCalibrationMessage.uid = d4Message->uid;
    selfCalibrationMessage.resultLen = d4Message->resultData.len;
    if (selfCalibrationMessage.resultLen > 0) {
        selfCalibrationMessage.resultData = (uint8_t *)malloc(selfCalibrationMessage.resultLen);
        memcpy(selfCalibrationMessage.resultData, d4Message->resultData.value, selfCalibrationMessage.resultLen);
        free(d4Message->resultData.value);
        d4Message->resultData.value = NULL;
    }
    selfCalibrationMessage.deviceModel.len = d4Message->deviceModel.len;
    if (selfCalibrationMessage.deviceModel.len > 0) {
        selfCalibrationMessage.deviceModel.value = (uint8_t *)malloc(selfCalibrationMessage.deviceModel.len);
        memcpy(selfCalibrationMessage.deviceModel.value, d4Message->deviceModel.value, selfCalibrationMessage.deviceModel.len);
        free(d4Message->deviceModel.value);
        d4Message->deviceModel.value = NULL;
    }
    buildSelfCalibrationMessage(&selfCalibrationMessage);
}

void BleKeyV3DataParser::parseRssiCollectMessage(BleKeyV3OutputMessage *outputMessage) {
    BleKeyV3ByteBaseMessage messageData = outputMessage->messageData;
    BleKeyV3CarStateD6 *d6Message = (BleKeyV3CarStateD6 *)messageData.value;

    RssiCollectMessage rssiCollectMessage;
    rssiCollectMessage.result = d6Message->result;
    rssiCollectMessage.direction = d6Message->direction;
    rssiCollectMessage.distance = d6Message->distance;
    rssiCollectMessage.uid = d6Message->uid;
    rssiCollectMessage.deviceModel.len = d6Message->deviceModel.len;
    if (rssiCollectMessage.deviceModel.len > 0) {
        rssiCollectMessage.deviceModel.value = (uint8_t *)malloc(rssiCollectMessage.deviceModel.len);
        memcpy(rssiCollectMessage.deviceModel.value, d6Message->deviceModel.value, rssiCollectMessage.deviceModel.len);
        free(d6Message->deviceModel.value);
        d6Message->deviceModel.value = NULL;
    }
    buildRssiCollectMessage(&rssiCollectMessage);
}

void BleKeyV3DataParser::parseParkingControlStateMessage(BleKeyV3OutputMessage *outputMessage) {
    BleKeyV3ByteBaseMessage messageData = outputMessage->messageData;
    BleKeyV3CarStateD8 *d8Message = (BleKeyV3CarStateD8 *)messageData.value;

    ParkingControlStateMessage parkingControlMessage;
    parkingControlMessage.result = d8Message->result;
    buildParkingControlStateMessage(&parkingControlMessage);
}

void BleKeyV3DataParser::parsePollingFuncStateMessage(BleKeyV3OutputMessage *outputMessage) {
    BleKeyV3ByteBaseMessage messageData = outputMessage->messageData;
    BleKeyV3CarStateD9 *d9Message = (BleKeyV3CarStateD9 *)messageData.value;

    PollingFuncStateMessage pollingFuncMessage;
    pollingFuncMessage.pollingUnlockState = d9Message->pollingUnlockState;
