void BleKeyV3DataParser::parseNumericMessage(BleKeyV3OutputMessage *outputMessage) {
    BleKeyV3ByteBaseMessage messageData = outputMessage->messageData;
    BleKeyV3CarStateD3 *d3Message = (BleKeyV3CarStateD3 *)messageData.value;

    CarNumDataMessage carNumDataMessage;
    carNumDataMessage.totalDistances = d3Message->totalDistances;
    carNumDataMessage.vcuMileage = d3Message->vcuMileage;
    carNumDataMessage.totalBatteryLife = d3Message->totalBatteryLife;
    carNumDataMessage.carSpeed = d3Message->carSpeed;
    carNumDataMessage.carSpeedState = d3Message->carSpeedState;
