19	unsigned char* bleHexStringToBytes(const char* hexString, size_t* length) {
20	    size_t hexStringLength = strlen(hexString);
21	    if (hexStringLength % 2 != 0) {
22	        // 如果字符串长度不是偶数，则返回NULL
23	        return NULL;
24	    }
25	    
26	    size_t byteLength = hexStringLength / 2;
27	    unsigned char* bytes = (unsigned char*)malloc(byteLength);
28	    if (bytes == NULL) {
29	        // 内存分配失败
30	        return NULL;
31	    }
32	    
33	    for (size_t i = 0, j = 0; i < hexStringLength; i += 2, j++) {
34	        // 将两个16进制字符转换为一个字节
35	        // 注意：这里假设输入的字符串是大写或小写，并通过tolower统一转换为小写
36	        unsigned char byte = 0;
37	        char byteString[3] = {0};
38	        strncpy(byteString, hexString + i, 2); // 复制两个字符
39	        sscanf(byteString, "%2hhx", &byte); // 读取两个十六进制字符并转换
40	        
41	        bytes[j] = byte;
42	    }
43	    
44	    if (length != NULL) {
45	        *length = byteLength;
46	    }
47	    
48	    return bytes;
49	}
