unsigned char* bleHexStringToBytes(const char* hexString, size_t* length) {
    size_t hexStringLength = strlen(hexString);
    if (hexStringLength % 2 != 0) {
        // 如果字符串长度不是偶数，则返回NULL
        return NULL;
    }

    size_t byteLength = hexStringLength / 2;
    unsigned char* bytes = (unsigned char*)malloc(byteLength);
    if (bytes == NULL) {
        // 内存分配失败
        return NULL;
    }

    for (size_t i = 0, j = 0; i < hexStringLength; i += 2, j++) {
        // 将两个16进制字符转换为一个字节
        // 注意：这里假设输入的字符串是大写或小写，并通过tolower统一转换为小写
        unsigned char byte = 0;
        char byteString[3] = {0};
        strncpy(byteString, hexString + i, 2); // 复制两个字符
        sscanf(byteString, "%2hhx", &byte); // 读取两个十六进制字符并转换

        bytes[j] = byte;
    }

    if (length != NULL) {
        *length = byteLength;
    }

    return bytes;
}


@implementation XPBleKeyV3DataProcessor

+ (NSString *)compactJsonString:(NSString *)str {
    NSString * compactResult = [str stringByReplacingOccurrencesOfString:@"\r" withString:@""];
    compactResult = [compactResult stringByReplacingOccurrencesOfString:@"\n" withString:@""];
    compactResult = [compactResult stringByReplacingOccurrencesOfString:@"\t" withString:@""];
    compactResult = [compactResult stringByReplacingOccurrencesOfString:@"\"" withString:@"\\\""];
    return compactResult;
}

+ (NSString *)cmdArrayToOCCode:(NSArray * _Nonnull)array {

    __block NSString * codeStr = @"@[";
    [array enumerateObjectsUsingBlock:^(id  _Nonnull obj, NSUInteger idx, BOOL * _Nonnull stop) {
        NSNumber * number = (NSNumber *)obj;
        if ([number isKindOfClass:[NSNumber class]]) {
            codeStr = [codeStr stringByAppendingFormat:@"@(%@), ", number];
        }
    }];

    codeStr = [codeStr stringByAppendingString:@"]"];

    return codeStr;
}

+ (NSString *)dataArrayToOCCode:(NSArray * _Nonnull)array {

    __block NSString * codeStr = @"@[";
    [array enumerateObjectsUsingBlock:^(id  _Nonnull obj, NSUInteger idx, BOOL * _Nonnull stop) {
        NSData *diretionData = (NSData *)obj;
        if ([diretionData isKindOfClass:[NSData class]]) {
            codeStr = [codeStr stringByAppendingFormat:@"[NSData dataWithHexString:@\"%@\"], ", [diretionData hexString]];
        }
    }];

    codeStr = [codeStr stringByAppendingString:@"]"];

    return codeStr;
}

+ (NSString *)parseBleKeyV3MessageWithVehicleCode:(NSString *)vehicleCode bleData:(NSData *)bleData sessionKey:(NSData *)sessionKey authKey:(NSData *)authKey isEncrypted:(BOOL)isEncrypted {
    DLogTagInfo(@"receive ble data", @"bleData:[NSData dataWithHexString:@\"%@\"] sessionKey:[NSData dataWithHexString:@\"%@\"] authKey:[NSData dataWithHexString:@\"%@\"] isEncrypted:%@];\n"
        , [bleData hexString], [sessionKey hexString], [authKey hexString], @(isEncrypted));
    try {
        uint8_t *dataPointer = (uint8_t *)bleData.bytes;
        const char *vehicleTypeCode = [vehicleCode UTF8String];
        const char *cString = parseBleKeyV3Protocol(vehicleTypeCode, (const uint8_t *)dataPointer, bleData.length, (uint8_t *)sessionKey.bytes, (int)sessionKey.length, (uint8_t *)authKey.bytes, authKey.length, (int)isEncrypted);
        if (cString == NULL) {
            return NULL;
        }
        NSString *result = [NSString stringWithUTF8String:cString];
        releaseBluetoothBuffer(cString);

    //    DLogTagInfo(@"XPBLEDataMake", @"单元测试：NSString *result = [XPBleKeyV3DataProcessor parseBleKeyV3MessageWithVehicleCode:@\"%@\" bleData:[NSData dataWithHexString:@\"%@\"] sessionKey:[NSData dataWithHexString:@\"%@\"] authKey:[NSData dataWithHexString:@\"%@\"] isEncrypted:%@];\r\nresult:%@", vehicleCode, [bleData hexString], [sessionKey hexString], [authKey hexString], @(isEncrypted), result);
        NSString * compactResult = [self compactJsonString:result];
        DLogTagInfo(@"XPBLEDataMake", @"parseBleKeyV3MessageWithVehicleCode result:%@", result);
        DLogTagInfo(@"XPBLEDataMake", @"提取单元测试：\nNSString *result = [XPBleKeyV3DataProcessor parseBleKeyV3MessageWithVehicleCode:@\"%@\" bleData:[NSData dataWithHexString:@\"%@\"] sessionKey:[NSData dataWithHexString:@\"%@\"] authKey:[NSData dataWithHexString:@\"%@\"] isEncrypted:%@];\n"
            "NSDictionary * testMergedDict = [self mergedDictFromParsedStr:result];\n"
