+ (NSData *)generateRescueAuth0DataIndictor:(NSString *)hexIndictor uid:(uint64_t)uid hexKeyId:(NSString *)hexKeyId rand0:(uint32_t)rand0 timeStamp:(uint64_t)timeStamp hexAuthKey:(NSString *)hexAuthKey {
    try {

        NSData *indicatorData = [NSData dataWithHexString:hexIndictor];
        NSData *keyIdData = [NSData dataWithHexString:hexKeyId];
        NSData *authKeyData = [NSData dataWithHexString:hexAuthKey];

        std::vector<uint8_t> indicatorVec = [self convertNSDataToVector:indicatorData];
        std::vector<uint8_t> keyIdVec = [self convertNSDataToVector:keyIdData];
        std::vector<uint8_t> authKeyVec = [self convertNSDataToVector:authKeyData];

        // 调用C++函数
        std::vector<uint8_t> packet = generateAuth0Packet(
            indicatorVec, rand0, uid, keyIdVec, timeStamp, authKeyVec
        );

        // 转换回NSData
        NSData *resultData = [NSData dataWithBytes:packet.data() length:packet.size()];
        DLogTagInfo(@"XPBLEDataMake", @"提取单元测试：\nNSData *result = [XPBleKeyV3DataProcessor generateRescueAuth0DataIndictor:@\"%@\" uid:%@ hexKeyId:@\"%@\" rand0:%@ timeStamp:%@ hexAuthKey:@\"%@\"];\n"
                    "NSString * testResultToHexStr = [result hexString];\n"
                    "NSString * testResultHexRight = @\"%@\"; // 当次执行结果 \n"
                    "XCTAssertTrue([testResultToHexStr isEqualToString:testResultHexRight]);\n",
                    hexIndictor, @(uid), hexKeyId, @(rand0), @(timeStamp), hexAuthKey, [resultData hexString]);
        return resultData;
    } catch (const std::exception& ) {
        DLogTagInfo(@"XPBLEDataMake", @"generateRescueAuth0DataIndictor failed with params: hexIndictor = %@, uid = %@, hexKeyId = %@, rand0 = %@, timeStamp = %@, hexAuthKey = %@", hexIndictor, @(uid), hexKeyId, @(rand0), @(timeStamp), hexAuthKey);
        return nil;
    }
}

+ (std::vector<uint8_t>)convertNSDataToVector:(NSData *)data {
    const uint8_t *bytes = static_cast<const uint8_t *>(data.bytes);
    return std::vector<uint8_t>(bytes, bytes + data.length);
}

