//  Pods
//
//  Created by huzy2 on 2024/9/6.
//

#ifndef BleKeyV3Header_h
#define BleKeyV3Header_h

extern const char * const commonResponseMessageHeader;
extern const char * const tboxRunStateMessageHeader;
extern const char * const carNumericDataMessageHeader;
extern const char * const selfCalibrationMessageHeader;
extern const char * const rssiCollectMessageHeader;
extern const char * const parkingControlStateMessageHeader;
extern const char * const chargeExtensionMessageHeader;

typedef struct CommonResponseMessage {
    uint32_t status = UINT32_MAX;
    uint32_t errorCode = UINT32_MAX;
    struct {
        uint8_t len = 0;
        uint8_t *value;
    }errorReason;
}__attribute__((packed)) CommonResponseMessage;

typedef struct CarNumDataMessage {
    uint32_t totalDistances = UINT32_MAX;
    uint8_t vcuMileage = 0xFF;
    uint16_t totalBatteryLife = UINT16_MAX;
    uint16_t carSpeed = UINT16_MAX;
    uint8_t carSpeedState = 0xFF;
}__attribute__((packed)) CarNumDataMessage;

typedef struct SelfCalibrationMessage {
    uint8_t result = 0xFF;
    uint8_t resultLen = 0;
    uint8_t *resultData;
    uint8_t direction = 0xFF;
    uint8_t distance = 0xFF;
    uint32_t uid = UINT32_MAX;
    struct {
        uint8_t len;
        uint8_t *value;
    }deviceModel;
}__attribute__((packed)) SelfCalibrationMessage;

typedef struct RssiCollectMessage {
    uint8_t result = 0xFF;
    uint8_t direction = 0xFF;
    uint8_t distance = 0xFF;
    uint32_t uid = UINT32_MAX;
    struct {
        uint8_t len;
        uint8_t *value;
    }deviceModel;
}__attribute__((packed)) RssiCollectMessage;

typedef struct ChargeExtensionMessage {
    uint8_t chargePortState = 0xFF;
    uint8_t chargePortAction = 0xFF;
    uint8_t powerBatteryState = 0xFF;
    uint8_t chargePortInsertState = 0xFF;
    uint8_t reserveChargeState = 0xFF;
}__attribute__((packed)) ChargeExtensionMessage;

typedef struct ParkingControlStateMessage {
    uint8_t result = 0xFF;
}__attribute__((packed)) ParkingControlStateMessage;

typedef struct PollingFuncStateMessage {
    uint8_t pollingUnlockState = 0xFF;
}__attribute__((packed)) PollingFuncStateMessage;


#endif /* BleKeyV3Header_h */

