    BLEKeyV3NotifyDeviceModel               = 0xC7,
    BLEKeyV3NotifyTypeParkingLimitDistance  = 0xC8,
    BLEKeyV3NotifyTypePollingEnableData     = 0xC9 
} BLEKeyV3NotifyType;

typedef enum BLEKeyV3Notify1Type: uint8_t {
    BLEKeyV3NotifyType1TboxState          = 0xDD,
