    BLEKeyV3CarStateTypeNumerical = 0xD3,
    BLEKeyV3CarStateTypeSelfCalibrationResult = 0xD4,
    BLEKeyV3CarStateTypeRssiCollectResult = 0xD6,
    BLEKeyV3CarStateTypeParkingLimitControlState = 0xD8,
