} BLEKeyV3Auth0RequestPollingConfigType;

typedef enum BLEKeyV3Auth0ResponseFactorType: uint8_t {
    BLEKeyV3Auth0ResponseFactorTypeRand01         = 0x01,
    BLEKeyV3Auth0ResponseFactorTypeRand1          = 0x02
} BLEKeyV3Auth0ResponseFactorType;

typedef enum BLEKeyV3Auth1RequestFactorType: uint8_t {
    BLEKeyV3Auth1RequestFactorTypeRand12              = 0x01,
    BLEKeyV3Auth1RequestFactorTypeCertMessage         = 0x02
} BLEKeyV3Auth1RequestFactorType;

typedef enum BLEKeyV3CarStateRKEType: uint8_t {
    BLEKeyV3CarStateRKETypeCancel   = 0x00,
    BLEKeyV3CarStateRKETypeCommon   = 0x01,
    BLEKeyV3CarStateRKETypeCharge   = 0x02,
    BLEKeyV3CarStateRKETypeParking  = 0x04,
    BLEKeyV3CarStateRKETypeNumrical = 0x08,
    BLEKeyV3CarStateRKETypeRssi     = 0x10
} BLEKeyV3CarStateRKEType;

typedef enum BLEKeyV3PollingFuncType: uint8_t {
    BLEKeyV3PollingFuncTypeNone            = 0x00,
    BLEKeyV3PollingFuncTypePollingUnlock   = 0x01
} BLEKeyV3PollingFuncType;

typedef enum BLEKeyV3RKEDataType: uint8_t {
