    BLEKeyV3MessageTypeNotification = 0x04,
    BLEKeyV3MessageTypeTest = 0x05,
    BLEKeyV3MessageTypeNotification1 = 0x14,
    BLEKeyV3MessageTypeRFU = 0xFF
} BLEKeyV3MessageType;

typedef enum BLEKeyV3ContentType: uint8_t {
    BLEKeyV3ContentTypeSingleType = 0x01,
    BLEKeyV3ContentTypeDualType = 0x02
} BLEKeyV3ContentType;

typedef struct BLEKeyV3Conent {
    BLEKeyV3ContentType contentType;
    uint8_t contentSize;
    uint16_t tag;
