BleKeyV3RtAuthRequestCreateResult createBleKeyV3RtAuthRequestWithInput(BleKeyV3RtAuthParams *rtAuthParams, uint8_t *rtAuthEncodeData, size_t *rtAuthEncodeDataSize) {
    __CHECK_RET(rtAuthParams != NULL, BleKeyV3RtAuthRequestCreateParamsIsNull)
    __CHECK_RET(rtAuthParams->certificate != NULL && rtAuthParams->certificateSize != 0, BleKeyV3RtAuthRequestCreateCertificateIsNull)
    __CHECK_RET(rtAuthParams->deviceModel != NULL && rtAuthParams->deviceModelSize != 0, BleKeyV3RtAuthRequestCreateDeviceModelIsNull)

    // 构造二级 TLV: certificate(0x01) + deviceModel(0x02)
    uint8_t *certificateTlvData = (uint8_t *)encodeTlvMessage(BLEKeyV3RtAuthRequestFactorTypeCertificate, rtAuthParams->certificateSize, rtAuthParams->certificate);
    uint8_t *deviceModelTlvData = (uint8_t *)encodeTlvMessage(BLEKeyV3RtAuthRequestFactorTypeDeviceModel, rtAuthParams->deviceModelSize, rtAuthParams->deviceModel);

    size_t certificateTlvSize = getTlvTotalSize(certificateTlvData);
    size_t deviceModelTlvSize = getTlvTotalSize(deviceModelTlvData);
    size_t innerDataLength = certificateTlvSize + deviceModelTlvSize;

    uint8_t *innerData = (uint8_t *)malloc(innerDataLength);
    memcpy(innerData, certificateTlvData, certificateTlvSize);
    memcpy(innerData + certificateTlvSize, deviceModelTlvData, deviceModelTlvSize);
    safe_free(certificateTlvData);
    safe_free(deviceModelTlvData);

    // 构造一级 TLV: tag=0x7F54
    uint8_t *rtAuthTlvData = (uint8_t *)encodeTlvMessage(BLEKeyV3RtAuthRequestTag, innerDataLength, innerData);
    safe_free(innerData);
    size_t rtAuthTlvSize = getTlvTotalSize(rtAuthTlvData);

    // 明文 — 不加密，直接构造 BLEKeyV3Message
    uint16_t checkSum = calc_crc16_ccitt(rtAuthTlvData, rtAuthTlvSize);
    uint16_t checkSumLittleEndian = host_int16_to_little_endian(checkSum);
    BLEKeyV3Message v3Message;
    v3Message.msgId = BLEKeyV3MessageTypeRtAuth;
    v3Message.msgLength = rtAuthTlvSize;
    v3Message.messageData = (uint8_t *)malloc(rtAuthTlvSize);
    memcpy(v3Message.messageData, rtAuthTlvData, rtAuthTlvSize);
    v3Message.checkSum = checkSumLittleEndian;
    safe_free(rtAuthTlvData);

    copyBleV3MessageRawData(&v3Message, rtAuthEncodeData);
    *rtAuthEncodeDataSize = sizeOfBLEKeyV3Message(&v3Message);
    free(v3Message.messageData);
    return BleKeyV3RtAuthRequestCreateSuccess;
}

