BleKeyV3Auth0RequestCreateResult getAuth0FactorTlvData(uint64_t uid, const uint8_t *keyIdData,size_t keyIdSize, uint32_t r0,uint64_t timeStamp,uint8_t **authFactorTlvResultData) {
    __CHECK_RET(keyIdData != NULL && keyIdSize != 0,BleKeyV3Auth0RequestCreateKeyIdIsNull)
    uint64_t uidLittleEndian = host_int64_to_little_endian(uid);
    uint8_t *uidTlvData = (uint8_t *)encodeTlvMessage(BLEKeyV3Auth0RequestFactorTypeUid, sizeof(uint64_t), &uidLittleEndian);

    uint8_t *keyIdTlvData = (uint8_t *)encodeTlvMessage(BLEKeyV3Auth0RequestFactorTypeKid,keyIdSize,keyIdData);

    uint32_t r0LittleEndian = host_int32_to_little_endian(r0);
    uint8_t *r0TlvData = (uint8_t *)encodeTlvMessage(BLEKeyV3Auth0RequestFactorTypeRand0, sizeof(uint32_t), &r0LittleEndian);

    uint64_t timeStampLittleEndian = host_int64_to_little_endian(timeStamp);
    uint8_t *timeStampTlvData = (uint8_t *)encodeTlvMessage(BLEKeyV3Auth0RequestFactorTypeTimeStamp, sizeof(uint64_t), &timeStampLittleEndian);
    size_t uidTlvDataSize = getTlvTotalSize(uidTlvData);
    size_t keyIdTlvDataSize = getTlvTotalSize(keyIdTlvData);
    size_t r0TlvDataSize = getTlvTotalSize(r0TlvData);
    size_t timeStampTlvDataSize = getTlvTotalSize(timeStampTlvData);
    size_t authFactorLength = uidTlvDataSize + keyIdTlvDataSize + r0TlvDataSize + timeStampTlvDataSize;
    uint8_t *authFactorData = (uint8_t *)malloc(authFactorLength);
    size_t offset = 0;
    memcpy(authFactorData+offset, uidTlvData, uidTlvDataSize);
    offset += uidTlvDataSize;
    memcpy(authFactorData+offset, keyIdTlvData, keyIdTlvDataSize);
    offset += keyIdTlvDataSize;
    memcpy(authFactorData+offset, r0TlvData, r0TlvDataSize);
    offset += r0TlvDataSize;
    memcpy(authFactorData+offset, timeStampTlvData,timeStampTlvDataSize);
    offset += timeStampTlvDataSize;
    safe_free(uidTlvData);
    safe_free(keyIdTlvData);
    safe_free(r0TlvData);
    safe_free(timeStampTlvData);
    uint8_t *authFactorTlvData = (uint8_t *)encodeTlvMessage(BLEKeyV3AuthDataTypeAuth0RequestFactor, authFactorLength, authFactorData);
    safe_free(authFactorData);
    *authFactorTlvResultData =  authFactorTlvData;
    return BleKeyV3Auth0RequestCreateSuccess;
}

BleKeyV3Auth1RequestCreateResult getAuth1FactorTlvData(uint32_t r12,uint8_t *certMessageData,size_t certMessageLength,uint8_t **authFactorTlvResultData) {
    __CHECK_RET(certMessageData != NULL && certMessageLength != 0,BleKeyV3Auth1RequestCreateCertMessageIsNull)
    uint32_t r12LittleEndian = host_int32_to_little_endian(r12);
    uint8_t *r12TlvData = (uint8_t *)encodeTlvMessage(BLEKeyV3Auth1RequestFactorTypeRand12, sizeof(r12LittleEndian), &r12LittleEndian);
    uint8_t *certMessageTlvData = (uint8_t *)encodeTlvMessage(BLEKeyV3Auth1RequestFactorTypeCertMessage, certMessageLength, certMessageData);
    size_t r12TlvDataSize = getTlvTotalSize(r12TlvData);
    size_t certMessageTlvDataSize = getTlvTotalSize(certMessageTlvData);
    size_t authFactorLength = r12TlvDataSize + certMessageTlvDataSize;
    uint8_t *authFactorData = (uint8_t *)malloc(authFactorLength);
    size_t offset = 0;
    memcpy(authFactorData+offset, r12TlvData, r12TlvDataSize);
    offset += r12TlvDataSize;
    memcpy(authFactorData+offset, certMessageTlvData, getTlvTotalSize(certMessageTlvData));
    offset += certMessageTlvDataSize;
    safe_free(r12TlvData);
