uint8_t * getPollingCustomeData(BleKeyV3PollingConfigParams *pollingConfigParams, uint8_t tag) {
    size_t pollingDataHeaderLength = sizeof(BleKeyV3PollingConfigParams) - sizeof(pollingConfigParams->selfCalibrationData);
