BleKeyV3Auth0RequestCreateResult getPollingConfigTlvData(BleKeyV3PollingConfigParams *pollingConfigParams, uint8_t pollingEnableSwitch, uint8_t *deviceModelData, size_t deviceModelLen, uint8_t *bleNameData, size_t bleNameLen, uint8_t **pollingConfigTlvResultData) {
