    size_t pollingTlvDataSize = getTlvTotalSize(pollingTlvData);
    size_t deviceModelTlvDataSize = getTlvTotalSize(deviceModelTlvData);
    size_t bleNameTlvDataSize = getTlvTotalSize(bleNameTlvData);
    size_t pollingEnableConfigTlvDataSize = getTlvTotalSize(pollingEnableConfigTlvData);
    uint8_t pollingConfigLenth = pollingTlvDataSize + deviceModelTlvDataSize + bleNameTlvDataSize + pollingEnableConfigTlvDataSize;
    uint8_t *pollingConfigData = (uint8_t *)malloc(pollingConfigLenth);
    uint8_t offset = 0;
    memcpy(pollingConfigData+offset, pollingTlvData, pollingTlvDataSize);
    offset += pollingTlvDataSize;
    memcpy(pollingConfigData+offset, deviceModelTlvData, deviceModelTlvDataSize);
    offset += deviceModelTlvDataSize;
    memcpy(pollingConfigData+offset, bleNameTlvData, bleNameTlvDataSize);
    offset += bleNameTlvDataSize;
    memcpy(pollingConfigData+offset, pollingEnableConfigTlvData, pollingEnableConfigTlvDataSize);
    offset += pollingEnableConfigTlvDataSize;

    safe_free(pollingTlvData);
    safe_free(deviceModelTlvData);
    safe_free(bleNameTlvData);
    safe_free(pollingEnableConfigTlvData);
    uint8_t *pollingConfigTlvData = (uint8_t *)encodeTlvMessage(BLEKeyV3AuthDataTypePollingConfig, pollingConfigLenth, pollingConfigData);
    safe_free(pollingConfigData);
    *pollingConfigTlvResultData = pollingConfigTlvData;
    return BleKeyV3Auth0RequestCreateSuccess;
}

