// auth0
BleKeyV3Auth0RequestCreateResult createBleKeyV3Auth0RequestWithInput(BleKeyV3Auth0Params *auth0Params, uint8_t pollingEnableSwitch, uint8_t *auth0EncodeData, size_t *auth0EncodeDataSize) {
    __CHECK_RET(auth0Params != NULL, BleKeyV3Auth0RequestCreateAuth0ParamsIsNull)
    __CHECK_RET(auth0Params->authKey != NULL, BleKeyV3Auth0RequestCreateAuth0ParamsIsNull)
    uint8_t *indicatorTlvData = (uint8_t *)encodeTlvMessage(BLEKeyV3AuthDataTypeIndictor, auth0Params->indicatorSize, auth0Params->indictor);
    __CHECK_RET(indicatorTlvData != NULL, BleKeyV3Auth0RequestCreateIndicatorIsNull)
    uint8_t *authFactorTlvData = NULL;
    BleKeyV3Auth0RequestCreateResult authFactorResult = getAuth0FactorTlvData(auth0Params->uid, auth0Params->keyId, auth0Params->keyIdSize, auth0Params->rand0, auth0Params->timeStamp,&authFactorTlvData);
    if (authFactorResult != BleKeyV3Auth0RequestCreateSuccess) {
        return authFactorResult;
    }
    uint8_t *pollingConfigTlvData = NULL;
    BleKeyV3Auth0RequestCreateResult pollingConfigResult = getPollingConfigTlvData(&auth0Params->pollingConfig, pollingEnableSwitch, auth0Params->deviceModel, auth0Params->deviceModelSize, auth0Params->bleName, auth0Params->bleNameSize,&pollingConfigTlvData);
    if (pollingConfigResult != BleKeyV3Auth0RequestCreateSuccess) {
        return authFactorResult;
    }
    size_t indicatorSize = getTlvTotalSize(indicatorTlvData);
    size_t authFactorSize = getTlvTotalSize(authFactorTlvData);
    size_t pollingConfigSize = getTlvTotalSize(pollingConfigTlvData);

    size_t rawDataSize = authFactorSize + pollingConfigSize ;
    memcpy(auth0EncodeData, authFactorTlvData, authFactorSize);
    memcpy(auth0EncodeData+authFactorSize, pollingConfigTlvData, pollingConfigSize);
    safe_free(authFactorTlvData);
    safe_free(pollingConfigTlvData);
//    DLogTagInfo(kBLEKeyTag, @"加密前数据:%@",[NSData dataWithBytes:rawData length:authFactorSize+pollingConfigSize].hexString);
    unsigned int encodeDataSize = 0;
    unsigned char iv_copy[16];
    memcpy(iv_copy, bleKeyV3IvData, 16);
    unsigned char *key = (unsigned char *)calloc(1, auth0Params->authKeySize);
    memcpy(key, auth0Params->authKey, auth0Params->authKeySize);
    unsigned char *encodedData = aes_256_cbc_encrypt((unsigned char *)auth0EncodeData, rawDataSize, key, (unsigned char *)iv_copy,&encodeDataSize);
    safe_free(key);
    size_t auth0DataLength = encodeDataSize + indicatorSize;
    memcpy(auth0EncodeData, indicatorTlvData, indicatorSize);
    memcpy(auth0EncodeData+indicatorSize, encodedData, encodeDataSize);
    safe_free(indicatorTlvData);
    uint16_t checkSum = calc_crc16_ccitt(auth0EncodeData,auth0DataLength);
    uint16_t checkSumLittleEndian = host_int16_to_little_endian(checkSum);
    BLEKeyV3Message v3Message;
    v3Message.msgId = BLEKeyV3MessageTypeAuth0;
    v3Message.msgLength = auth0DataLength;
    v3Message.messageData = (uint8_t *)malloc(auth0DataLength);
    memcpy(v3Message.messageData, auth0EncodeData, auth0DataLength);
    v3Message.checkSum = checkSumLittleEndian;
    copyBleV3MessageRawData(&v3Message,auth0EncodeData);
    *auth0EncodeDataSize = sizeOfBLEKeyV3Message(&v3Message);
    return BleKeyV3Auth0RequestCreateSuccess;
}


