// rke
BleKeyV3RkeRequestCreateResult createBleKeyV3RkeRequestWithInput(BleKeyV3RkeParams *rkeParams,int isSecure,uint8_t *rkeEncodeData,size_t *rkeEncodeDataSize) {
    __CHECK_RET(rkeParams != NULL, BleKeyV3RkeRequestCreateRkeParamsIsNull)
    __CHECK_RET(rkeParams->rkeData != NULL && rkeParams->rkeDataSize != 0, BleKeyV3RkeRequestCreateRkeDataIsNull)
    uint8_t *rkeTlvData = NULL;
    BleKeyV3RkeRequestCreateResult rkeDataResult = getRKEDataWithRkeType(rkeParams->rkeType, rkeParams->rkeId, rkeParams->rkeData, rkeParams->rkeDataSize,&rkeTlvData);
    if (rkeDataResult != BleKeyV3RkeRequestCreateSuccess) {
        return rkeDataResult;
    }
    size_t rkeTlvSize = getTlvTotalSize(rkeTlvData);
    if (isSecure) {
        __CHECK_RET(rkeParams->sessionKey != NULL && rkeParams->sessionKeySize != 0, BleKeyV3RkeRequestCreateSessionKeyIsNull)
        __CHECK_RET(rkeParams->hmacKey != NULL && rkeParams->hmacKeySize != 0, BleKeyV3RkeRequestCreateHmacKeyIsNull)
        size_t xorResultSize = 0;
        uint8_t * sessionXorResult = getXorResult((unsigned int *)&xorResultSize, rkeTlvData, rkeTlvSize, rkeParams->sessionKey, rkeParams->sessionKeySize);
        size_t hmacDataSize = 0;
        uint8_t *hmacData = hmac_sha256(rkeParams->hmacKey, rkeParams->hmacKeySize, rkeTlvData, rkeTlvSize, (unsigned int *)&hmacDataSize);
        safe_free(rkeTlvData);
        size_t authedDataLength = xorResultSize + hmacDataSize;
        memcpy(rkeEncodeData, sessionXorResult, xorResultSize);
        memcpy(rkeEncodeData+xorResultSize, hmacData, hmacDataSize);
        safe_free(sessionXorResult);
        safe_free(hmacData);
        uint16_t checkSum = calc_crc16_ccitt(rkeEncodeData,authedDataLength);
        uint16_t checkSumLittleEndian = host_int16_to_little_endian(checkSum);
        BLEKeyV3Message v3Message;
        v3Message.msgId = BLEKeyV3MessageTypeRKE;
        v3Message.msgLength = authedDataLength;
        v3Message.messageData = (uint8_t *)malloc(authedDataLength);
        memcpy(v3Message.messageData, rkeEncodeData, authedDataLength);
        v3Message.checkSum = checkSumLittleEndian;
        copyBleV3MessageRawData(&v3Message,rkeEncodeData);
        *rkeEncodeDataSize = sizeOfBLEKeyV3Message(&v3Message);
        return BleKeyV3RkeRequestCreateSuccess;
    } else {
        uint16_t checkSum = calc_crc16_ccitt(rkeTlvData,rkeTlvSize);
        uint16_t checkSumLittleEndian = host_int16_to_little_endian(checkSum);
        BLEKeyV3Message v3Message;
        v3Message.msgId = BLEKeyV3MessageTypeRKE;
        v3Message.msgLength = rkeTlvSize;
        v3Message.messageData = (uint8_t *)malloc(rkeTlvSize);
        memcpy(v3Message.messageData, rkeTlvData, rkeTlvSize);
        v3Message.checkSum = checkSumLittleEndian;
        copyBleV3MessageRawData(&v3Message,rkeEncodeData);
        *rkeEncodeDataSize = sizeOfBLEKeyV3Message(&v3Message);
        return BleKeyV3RkeRequestCreateSuccess;
    }
}

