void handleTlvLevel2Data(BLEKeyV3Conent *level2Data,BleKeyV3OutputMessage *outputMessage) {
    __CHECK(outputMessage != NULL);
    switch (outputMessage->messageType) {
        case BleKeyV3OutputMessageTypeRkeResponse:
            handleRkeResponseTlvData(level2Data->tag, level2Data->contentData, level2Data->contentDataLength, (BleKeyV3RkeResponse *)outputMessage->messageData.value);
            break;
        case BleKeyV3OutputMessageTypeAuth0Response:
            handleAuth0ResponseTlvData(level2Data->tag, level2Data->contentData, level2Data->contentDataLength, (BleKeyV3Auth0Response *)outputMessage->messageData.value);
            break;

