#ifndef BleKeyV3DataParser_hpp
#define BleKeyV3DataParser_hpp

#include <stdio.h>

#include "BaseDataParser.hpp"
#include "BLEKeyV3DecodeMessage.hpp"
#include "BleKeyV3Header.h"

class BleKeyV3DataParser: public BaseDataParser {

public:

