#include "BleKeyV3DataParser.hpp"
#include "../tools/log/log.h"
#include <string.h>
#include "../tools/tools.hpp"
#include "../tools/DataCovertTool.h"
#include "BLERescueKeyDataParser.hpp"

const char * const commonResponseMessageHeader = "commonResponse";
const char * const tboxRunStateMessageHeader = "tboxRunState";
const char * const carNumericDataMessageHeader = "carNumeric";
const char * const selfCalibrationMessageHeader = "selfCalirationData";
const char * const rssiCollectMessageHeader = "rssiCollectData";
const char * const parkingControlStateMessageHeader = "parkingControl";
const char * const chargeExtensionMessageHeader = "chargeExtension";
const char * const pollingFuncStateMessageHeader = "pollingFuncState";

using namespace SDKBleKeyV3;

uint8_t convertWindowState(uint8_t originValue) {
    return (200 - originValue) / 2;
}

uint8_t covertTrunkState(uint8_t originValue) {
    if (3 == originValue) {
        return 1;
    } else if (originValue == 0) {
        return 0xFF;
    } else if (originValue == 1) {
        return 0;
    } else if (originValue == 2) {
        return 3;
    } else if (originValue == 4) {
        return 2;
    } else {
        return originValue;
    }
}

uint8_t covertExtDoorState(uint8_t originValue) {
    if (originValue == 1) {
        return CarScissorsDoorStateClose;
    } else if (originValue == 2) {
        return CarScissorsDoorStateOpening;
    } else if (originValue == 3) {
        return CarScissorsDoorStateClosing;
    } else if (originValue == 4) {
        return CarScissorsDoorStateStop;
    } else if (originValue == 5) {
        return CarScissorsDoorStateOpen;
    } else {
        return CarScissorsDoorStateNotAvailable;
    }
}



void BleKeyV3DataParser::buildCommonResponseMessage(CommonResponseMessage *commonResponse) {
    kCarEventStart(common, commonResponseMessageHeader)
    kAddUInt32ItemToJson(common, "commonStatus", commonResponse->status);
    kAddUInt32ItemToJson(common, "commonErrorCode", commonResponse->errorCode);
    if (commonResponse->errorReason.len != 0) {
        char * reason = (char *)calloc(1, commonResponse->errorReason.len + 1);
        memcpy(reason, commonResponse->errorReason.value, commonResponse->errorReason.len);
        cJSON_AddStringToObject(common, "commonErrorReason", reason);
        safe_free(reason);
        safe_free(commonResponse->errorReason.value);
    }
    kCarEventEnd(common, this->resultArray);
}

void BleKeyV3DataParser::buildCarNumDataMessage(CarNumDataMessage *carNumData) {
    kVehicleStateStart(carNum)
    kAddUInt32ItemToJson(carNum, "totalDistances", carNumData->totalDistances);
    kAddUInt8ItemToJson(carNum, "vcuMileage", carNumData->vcuMileage);
    kAddUInt16ItemToJson(carNum, "totalBatteryLife", carNumData->totalBatteryLife);
    kAddUInt16ItemToJson(carNum, "carSpeed", carNumData->carSpeed);
    kAddUInt8ItemToJson(carNum, "carSpeedState", carNumData->carSpeedState);
    kVehicleStateEnd(carNumericDataMessageHeader, carNum, this->resultArray)
}

void BleKeyV3DataParser::buildSelfCalibrationMessage(SelfCalibrationMessage *selfCalibrationData) {
    kCarEventStart(selfCalibration, selfCalibrationMessageHeader)
    kAddUInt8ItemToJson(selfCalibration, "result", selfCalibrationData->result);
    kAddUInt8ItemToJson(selfCalibration, "resultLen", selfCalibrationData->resultLen);
    if (selfCalibrationData->resultLen != 0) {

        uint8_t length = sizeof(selfCalibrationData->direction) + sizeof(selfCalibrationData->resultLen) + selfCalibrationData->resultLen;
        uint8_t *uploadData = (uint8_t *)malloc(length);

        memcpy(uploadData, &selfCalibrationData->direction, sizeof(selfCalibrationData->direction));
        memcpy(uploadData + sizeof(selfCalibrationData->direction), &selfCalibrationData->resultLen, sizeof(selfCalibrationData->resultLen));
        memcpy(uploadData + sizeof(selfCalibrationData->direction) + sizeof(selfCalibrationData->resultLen), selfCalibrationData->resultData, selfCalibrationData->resultLen);

        char *hexStr = (char *)calloc(1, length * 2 + 1);
        bytesToHexString(uploadData, length, hexStr);
        cJSON_AddStringToObject(selfCalibration, "resultData", hexStr);
        safe_free(hexStr);
        safe_free(uploadData);
        safe_free(selfCalibrationData->resultData);
    }
    kAddUInt8ItemToJson(selfCalibration, "direction", selfCalibrationData->direction);
    kAddUInt8ItemToJson(selfCalibration, "distance", selfCalibrationData->distance);
    kAddUInt32ItemToJson(selfCalibration, "uid", selfCalibrationData->uid);
    if (selfCalibrationData->deviceModel.len != 0) {
        char * deviceModel = (char *)calloc(1, selfCalibrationData->deviceModel.len + 1);
        memcpy(deviceModel, selfCalibrationData->deviceModel.value, selfCalibrationData->deviceModel.len);
        cJSON_AddStringToObject(selfCalibration, "deviceModel", deviceModel);
        safe_free(deviceModel);
        safe_free(selfCalibrationData->deviceModel.value);
    }
    kCarEventEnd(selfCalibration, this->resultArray);
}

void BleKeyV3DataParser::buildRssiCollectMessage(RssiCollectMessage *rssiCollectData) {
    kCarEventStart(rssiCollect, rssiCollectMessageHeader)
    kAddUInt8ItemToJson(rssiCollect, "result", rssiCollectData->result);
    kAddUInt8ItemToJson(rssiCollect, "direction", rssiCollectData->direction);
    kAddUInt8ItemToJson(rssiCollect, "distance", rssiCollectData->distance);
    kAddUInt32ItemToJson(rssiCollect, "uid", rssiCollectData->uid);
    if (rssiCollectData->deviceModel.len != 0) {
        char * deviceModel = (char *)calloc(1, rssiCollectData->deviceModel.len + 1);
        memcpy(deviceModel, rssiCollectData->deviceModel.value, rssiCollectData->deviceModel.len);
        cJSON_AddStringToObject(rssiCollect, "deviceModel", deviceModel);
        safe_free(deviceModel);
        safe_free(rssiCollectData->deviceModel.value);
    }
    kCarEventEnd(rssiCollect, this->resultArray);
}

void BleKeyV3DataParser::buildChargeExtensionMessage(ChargeExtensionMessage *chargeExtensionData) {
    kVehicleStateStart(chargeExtension)
    kAddUInt8ItemToJson(chargeExtension, "chargePortState", chargeExtensionData->chargePortState);
    kAddUInt8ItemToJson(chargeExtension, "chargePortAction", chargeExtensionData->chargePortAction);
    kAddUInt8ItemToJson(chargeExtension, "powerBatteryState", chargeExtensionData->powerBatteryState);
    kAddUInt8ItemToJson(chargeExtension, "chargePortInsertState", chargeExtensionData->chargePortInsertState);
