void BleKeyV3DataParser::parseAuth0Response(BleKeyV3OutputMessage *outputMessage) {
    BleKeyV3ByteBaseMessage messageData = outputMessage->messageData;
    BleKeyV3Auth0Response *auth0Response = (BleKeyV3Auth0Response *)messageData.value;

    Auth0ResponseMessage auth0ResponseMessage;
    if (auth0Response->rand01.len > sizeof(auth0ResponseMessage.rand01) || auth0Response->rand1.len > sizeof(auth0ResponseMessage.rand1)) {
        XP_LOG_INFO("BleKeyV3", "protocol len error,need bigger Auth0ResponseMessage");
    } else {
        auth0ResponseMessage.rand01 = auth0Response->rand01.value;
        auth0ResponseMessage.rand1 = auth0Response->rand1.value;
    }
    buildAuth0ResponseMessage(&auth0ResponseMessage);
}

void BleKeyV3DataParser::parseCommonCarState(BleKeyV3OutputMessage *outputMessage) {
    BleKeyV3ByteBaseMessage messageData = outputMessage->messageData;
    BleKeyV3CarStateD0 *commonCarStates = (BleKeyV3CarStateD0 *)messageData.value;

    DoorMessage doorMessage;
    doorMessage.driver_door_lock_st = commonCarStates->lockState;
    doorMessage.driver_door_ajar_st = commonCarStates->leftFrontDoorState;
    doorMessage.passenger_door_ajar_st = commonCarStates->rightFrontDoorState;
    doorMessage.rear_left_door_ajar_st = commonCarStates->leftBackDoorState;
    doorMessage.rear_right_door_ajar_st = commonCarStates->rightBackDoorState;
    doorMessage.trunk_ajar_st = covertTrunkState(commonCarStates->trunckState);
    doorMessage.bonnet_ajar_st = commonCarStates->bonnetAjarState;
    doorMessage.temp_lock_st = commonCarStates->tempeoryLockState;
    doorMessage.trunk_ajar_st_new = commonCarStates->trunckActionState;
    doorMessage.left_slide_door_status = commonCarStates->leftSlideState;
    doorMessage.left_slide_door_position = commonCarStates->leftSlideOpenDegree;
    doorMessage.right_slide_door_status = commonCarStates->rightSlideState;
    doorMessage.right_slide_door_position = commonCarStates->rightSlideOpenDegree;
    doorMessage.front_left_power_door = commonCarStates->leftFrontElecDoorState;
    doorMessage.rear_left_power_door = commonCarStates->leftBackElecDoorState;
    doorMessage.front_right_power_door = commonCarStates->rightFrontElecDoorState;
    doorMessage.rear_right_power_door = commonCarStates->rightBackElecDoorState;
    doorMessage.super_lock_status = commonCarStates->superLockState;
    buildDoorMessage(&doorMessage);

    WindowMessage windowMessage;
    windowMessage.front_left_window_position = convertWindowState(commonCarStates->leftFrontWindowDegree);
    windowMessage.front_right_window_position = convertWindowState(commonCarStates->rightFrontWindowDegree);
    windowMessage.rear_left_window_position = convertWindowState(commonCarStates->leftBackWindowDegree);
    windowMessage.rear_right_window_position = convertWindowState(commonCarStates->rightBackWindowDegree);
    buildWindowMessage(&windowMessage);

    ExtDoorMessage extDoorMessage;
    extDoorMessage.mainDoorState = covertExtDoorState(commonCarStates->mainExtDoorState);
    extDoorMessage.subDoorState = covertExtDoorState(commonCarStates->subExtDoorState);
    buildExtDoorMessage(&extDoorMessage);

    TrailerHookStateMessage trailerHookMessage;
    trailerHookMessage.hook_status = commonCarStates->trailerHookState;
    trailerHookMessage.hook_machine_status = commonCarStates->trailerHookMachineState;
    trailerHookMessage.hook_system_monitor = commonCarStates->trailerHookSystemState;
    buildTrailerHookStateMessage(&trailerHookMessage);

    WireControlStateMessage wireControlMessage;
    wireControlMessage.wire_control_mode = commonCarStates->wireControlModeState;
    buildWireControlStateMessage(&wireControlMessage);

}

