void BleKeyV3DataParser::parseSelfCalibrationMessage(BleKeyV3OutputMessage *outputMessage) {
    BleKeyV3ByteBaseMessage messageData = outputMessage->messageData;
    BleKeyV3CarStateD4 *d4Message = (BleKeyV3CarStateD4 *)messageData.value;

    SelfCalibrationMessage selfCalibrationMessage;
    selfCalibrationMessage.result = d4Message->result;
    selfCalibrationMessage.direction = d4Message->direction;
    selfCalibrationMessage.distance = d4Message->distance;
