cJSON * BleKeyV3DataParser::parse(const uint8_t* data, size_t dataSize,uint8_t *sessionKey,size_t sessionKeySize,uint8_t *authKey,size_t authKeySize,int isEncrypted) {
    // 应急钥匙报文判断
    if (isRescueBleKeyV3Message(data, dataSize)) {
        return parseRescueBleKeyV3Message(data, dataSize, sessionKey, sessionKeySize, authKey, authKeySize, isEncrypted);
    }

    BleKeyV3CanMessageParams canMessageParams;
    canMessageParams.isEncrypted = (uint8_t)isEncrypted;
    canMessageParams.canMessage.len = dataSize;
    canMessageParams.canMessage.value = (uint8_t *)malloc(dataSize);
    memcpy(canMessageParams.canMessage.value, data, dataSize);
    if (isEncrypted) {
        canMessageParams.authKeyMessage.len = authKeySize;
        canMessageParams.authKeyMessage.value = (uint8_t *)malloc(authKeySize);
        memcpy(canMessageParams.authKeyMessage.value, authKey, authKeySize);
        canMessageParams.sessionKeyMessage.len = sessionKeySize;
        canMessageParams.sessionKeyMessage.value = (uint8_t *)malloc(sessionKeySize);
        memcpy(canMessageParams.sessionKeyMessage.value, sessionKey, sessionKeySize);
    }
    BleKeyV3OutputMessageParams outputMessageParams;
    decodeBleKeyV3CanMessage(&canMessageParams,&outputMessageParams);
    if (outputMessageParams.result != BleKeyV3DecodeV3CanMessageSuccess || outputMessageParams.outputSize <= 0) {
        return NULL;
    }
    for (int i = 0; i<outputMessageParams.outputSize; i++) {
        BleKeyV3OutputMessage &outputMessage = outputMessageParams.outputMessages[i];
        if (outputMessage.messageType == BleKeyV3OutputMessageTypeCommonStatus ||
            outputMessage.messageType == BleKeyV3OutputMessageTypeCommonErrorCode ||
            outputMessage.messageType == BleKeyV3OutputMessageTypeCommonErrorReason) {
            this->specialMessages.push_back(outputMessage);
        } else {
            this->parseSingleMessage(&outputMessage);
        }
    }
    this->parseSpecialMessage();

    if (canMessageParams.canMessage.value != NULL) {
        free(canMessageParams.canMessage.value);
        canMessageParams.canMessage.value = NULL;
    }
    if (isEncrypted) {
        if (canMessageParams.sessionKeyMessage.value != NULL) {
            free(canMessageParams.sessionKeyMessage.value);
            canMessageParams.sessionKeyMessage.value = NULL;
        }
        if (canMessageParams.authKeyMessage.value != NULL) {
            free(canMessageParams.authKeyMessage.value);
            canMessageParams.authKeyMessage.value = NULL;
        }
    }
    freeBleV3OutputMessages(&outputMessageParams);

    cJSON *result = parserEnd();
    return result;
}

void BleKeyV3DataParser::parseSpecialMessage() {
    if (this->specialMessages.size() == 0) {
        return;
    }
    CommonResponseMessage commonResponseMessage;
    for (const auto &outputMessage : this->specialMessages) {
        switch (outputMessage.messageType) {
            case BleKeyV3OutputMessageTypeCommonStatus:
                memcpy(&commonResponseMessage.status, outputMessage.messageData.value, sizeof(commonResponseMessage.status));
                break;
            case BleKeyV3OutputMessageTypeCommonErrorCode:
                memcpy(&commonResponseMessage.errorCode, outputMessage.messageData.value, sizeof(commonResponseMessage.errorCode));
                break;
            case BleKeyV3OutputMessageTypeCommonErrorReason:
                commonResponseMessage.errorReason.len = outputMessage.messageData.len;
                if (outputMessage.messageData.len > 0) {
                    commonResponseMessage.errorReason.value = (uint8_t *)calloc(1, commonResponseMessage.errorReason.len + 1);
                    memcpy(commonResponseMessage.errorReason.value, outputMessage.messageData.value, commonResponseMessage.errorReason.len);
                }
                break;

            default:
                break;
        }
    }
    buildCommonResponseMessage(&commonResponseMessage);
}

void BleKeyV3DataParser::parseSingleMessage(BleKeyV3OutputMessage *outputMessage) {
    switch (outputMessage->messageType) {
        case BleKeyV3OutputMessageTypeAuth0Response:
        {
            parseAuth0Response(outputMessage);
        }
            break;
        case BleKeyV3OutputMessageTypeCommonCarState:
        {
            parseCommonCarState(outputMessage);
        }
            break;
        case BleKeyV3OutputMessageTypeChargeState:
        {
            parseChargeState(outputMessage);
        }
            break;
        case BleKeyV3OutputMessageTypeParkingState:
        {
            parseBleXpuParkingState(outputMessage);
        }
            break;
        case BleKeyV3OutputMessageTypeNumeric:
        {
            parseNumericMessage(outputMessage);
        }
            break;
        case BleKeyV3OutputMessageTypeSelfCalibration:
        {
            parseSelfCalibrationMessage(outputMessage);
        }
            break;
        case BleKeyV3OutputMessageTypeRssiCollect:
        {
            parseRssiCollectMessage(outputMessage);
        }
            break;
        case BleKeyV3OutputMessageTypeParkingControlState:
        {
            parseParkingControlStateMessage(outputMessage);
        }
            break;
        case BleKeyV3OutputMessageTypePollingFuncState:
        {
            parsePollingFuncStateMessage(outputMessage);
        }
            break;
        case BleKeyV3OutputMessageTypeRkeResponse:
        {
            parseRkeResponseMessage(outputMessage);
        }
            break;

        default:
            break;
    }
}

