+ (NSData *_Nullable)generateRtAuthRequestData:(NSData * _Nonnull)certificate
                                   deviceModel:(NSString * _Nonnull)deviceModel {
    if (!certificate || certificate.length == 0) {
        DLogTagInfo(@"XPBLEDataMake", @"generateRtAuthRequestData: certificate is nil or empty");
        return nil;
    }
    if (!deviceModel || deviceModel.length == 0) {
        DLogTagInfo(@"XPBLEDataMake", @"generateRtAuthRequestData: deviceModel is nil or empty");
        return nil;
    }
    NSData *deviceModelData = [deviceModel dataUsingEncoding:NSUTF8StringEncoding];
    BleKeyV3RtAuthParams rtAuthParams = {
        (uint8_t *)certificate.bytes, (uint8_t)certificate.length,
        (uint8_t *)deviceModelData.bytes, (uint8_t)deviceModelData.length
    };
    uint8_t *rtAuthEncodeData = (uint8_t *)malloc(most_trans_count_size);
    size_t rtAuthEncodeDataSize = most_trans_count_size;
    BleKeyV3RtAuthRequestCreateResult result = createBleKeyV3RtAuthRequestWithInput(&rtAuthParams, rtAuthEncodeData, &rtAuthEncodeDataSize);
    NSData *resultData = [NSData dataWithBytes:rtAuthEncodeData length:rtAuthEncodeDataSize];
    if (rtAuthEncodeData != NULL) {
        free(rtAuthEncodeData);
    }
    if (result == BleKeyV3RtAuthRequestCreateSuccess) {
        DLogTagInfo(@"XPBLEDataMake", @"generateRtAuthRequestData success, certificate len:%lu, deviceModel:%@, result:%@",
                    (unsigned long)certificate.length, deviceModel, [resultData hexString]);
        return resultData;
    } else {
        DLogTagInfo(@"XPBLEDataMake", @"generateRtAuthRequestData result:<nil> certificate len:%lu, deviceModel:%@",
                    (unsigned long)certificate.length, deviceModel);
        return nil;
    }
}

