+ (NSData *_Nullable)generateAuth0DataIndictor:(NSString * _Nonnull)hexIndictor
                                           uid:(uint64_t)uid
                                      hexKeyId:(NSString * _Nonnull)hexKeyId
                                         rand0:(uint32_t)rand0
                                     timeStamp:(uint64_t)timeStamp
                                     isWelcome:(BOOL)isWelcome
                                 pollingSwitch:(uint8_t)pollingSwitch
                           pollingEnableSwitch:(BOOL)pollingEnableSwitch
                                unlockDistance:(float)unlockDistance
                                  lockDistance:(float)lockDistance
                            selfCalibrationLen:(uint8_t)selfCalibrationLen
                          selfCalibrationArray:(NSArray * _Nullable)selfCalibrationArray
                                   deviceModel:(NSString * _Nonnull)deviceModel
                                       bleName:(NSString * _Nonnull)bleName
                                    hexAuthKey:(NSString * _Nonnull)hexAuthKey
{
    size_t indicatorSize = 0;
    unsigned char * indictor = bleHexStringToBytes([hexIndictor cString], &indicatorSize);
    size_t keyIdSize = 0;
    unsigned char * keyId = bleHexStringToBytes([hexKeyId cString], &keyIdSize);
    uint8_t pollingUnlockDistance = (uint8_t)(unlockDistance + 0.5);
    uint8_t pollingLockDistance = (uint8_t)(lockDistance + 0.5);
    uint8_t *selfCalibrationData = NULL;
    if (selfCalibrationLen) {
        uint8_t len = 0;
        for (NSData *diretionData in selfCalibrationArray) {
            len += diretionData.length;
        }
        selfCalibrationData = (uint8_t *)malloc(len);
        uint8_t dataLen = 0;
        for (NSData *diretionData in selfCalibrationArray) {
            memcpy(selfCalibrationData+dataLen, diretionData.bytes, diretionData.length);
            dataLen += diretionData.length;
        }
    }
    NSData *deviceModelData = [deviceModel dataUsingEncoding:NSUTF8StringEncoding];
    NSData *bleNameData = [bleName dataUsingEncoding:NSUTF8StringEncoding];
    size_t authKeySize = 0;
    unsigned char * authKey = bleHexStringToBytes([hexAuthKey cString],&authKeySize);
    BleKeyV3PollingConfigParams pollingConfigParams = {
      isWelcome, pollingSwitch, pollingUnlockDistance, pollingLockDistance, selfCalibrationLen, selfCalibrationData
    };
    BleKeyV3Auth0Params auth0Params = {
        (uint8_t *)indictor, (uint8_t)indicatorSize, uid, keyId, (uint8_t)keyIdSize, rand0, timeStamp,
         pollingConfigParams,
         (uint8_t *)deviceModelData.bytes, (uint8_t)deviceModelData.length,
         (uint8_t *)bleNameData.bytes, (uint8_t)bleNameData.length,
         authKey, (uint8_t)authKeySize
    };
    uint8_t *auth0EncodeData = (uint8_t *)malloc(most_trans_count_size);
    size_t auth0EncodeDataSize = most_trans_count_size;
    BleKeyV3Auth0RequestCreateResult result = createBleKeyV3Auth0RequestWithInput(&auth0Params, pollingEnableSwitch, auth0EncodeData, &auth0EncodeDataSize);
    if (selfCalibrationData != NULL) {
        free(selfCalibrationData);
    }
    if (indictor != NULL) {
        free(indictor);
    }
    if (keyId != NULL) {
        free(keyId);
    }
    if (authKey != NULL) {
        free(authKey);
    }
    NSData *resultData = [NSData dataWithBytes:auth0EncodeData length:auth0EncodeDataSize];
    if (auth0EncodeData != NULL) {
        free(auth0EncodeData);
    }
    if (result == BleKeyV3Auth0RequestCreateSuccess) {
        DLogTagInfo(@"XPBLEDataMake", @"提取单元测试：\nNSData *result = [XPBleKeyV3DataProcessor generateAuth0DataIndictor:@\"%@\" uid:%@ hexKeyId:@\"%@\" rand0:%@ timeStamp:%@ isWelcome:%@ pollingSwitch:%@ pollingEnableSwitch:%@ unlockDistance:%@ lockDistance:%@ selfCalibrationLen:%@ selfCalibrationArray:%@ deviceModel:@\"%@\" bleName:@\"%@\" hexAuthKey:@\"%@\"];\n"
                    "NSString * testResultToHexStr = [result hexString];\n"
                    "NSString * testResultHexRight = @\"%@\"; // 当次执行结果 \n"
                    "XCTAssertTrue([testResultToHexStr isEqualToString:testResultHexRight]);\n", hexIndictor, @(uid), hexKeyId, @(rand0), @(timeStamp), @(isWelcome), @(pollingSwitch), @(pollingEnableSwitch), @(unlockDistance), @(lockDistance), @(selfCalibrationLen), [self dataArrayToOCCode:selfCalibrationArray], deviceModel, bleName, hexAuthKey, [resultData hexString]);
        return resultData;
    } else {
        DLogTagInfo(@"XPBLEDataMake", @"generateAuth0DataIndictor result:<nil> [XPBleKeyV3DataProcessor generateAuth0DataIndictor:@\"%@\" uid:%@ hexKeyId:@\"%@\" rand0:%@ timeStamp:%@ isWelcome:%@ pollingSwitch:%@ pollingEnableSwitch:%@ unlockDistance:%@ lockDistance:%@ selfCalibrationLen:%@ selfCalibrationArray:%@ deviceModel:@\"%@\" bleName:@\"%@\" hexAuthKey:@\"%@\"]", hexIndictor, @(uid), hexKeyId, @(rand0), @(timeStamp), @(isWelcome), @(pollingSwitch), @(pollingEnableSwitch), @(unlockDistance), @(lockDistance), @(selfCalibrationLen), [self dataArrayToOCCode:selfCalibrationArray], deviceModel, bleName, hexAuthKey);
        return nil;
    }
}

