+ (NSData *)generateHmacKey:(NSString * _Nonnull)hexAuthKey
                     rand01:(uint32_t)rand01
                     rand12:(uint32_t)rand12 {
    size_t authKeySize = 0;
    unsigned char * authKey = bleHexStringToBytes([hexAuthKey cString],&authKeySize);
    unsigned int hmacKeySize;
    unsigned char iv_copy[16];
    memcpy(iv_copy, bleKeyV3IvData, 16);
    unsigned char *hmacKey = getHmacKey((const uint8_t *)authKey, authKeySize, rand01, rand12, iv_copy, &hmacKeySize);
    NSData *hmacKeyData = [NSData dataWithBytes:hmacKey length:hmacKeySize];
    free(authKey);
    free(hmacKey);

    DLogTagInfo(@"XPBLEDataMake", @"提取单元测试：\nNSData *result = [XPBleKeyV3DataProcessor generateHmacKey:@\"%@\" rand01:%@ rand12:%@];\n"
        "NSString * testResultToHexStr = [result hexString];\n"
        "NSString * testResultHexRight = @\"%@\"; // 当次执行结果 \n"
        "XCTAssertTrue([testResultToHexStr isEqualToString:testResultHexRight]);\n",
                hexAuthKey, @(rand01), @(rand12), [hmacKeyData hexString]);
    return hmacKeyData;
}

