+ (NSData *)createTboxMessageV3:(uint8_t)controlId
                 controlCommand:(uint8_t)controlCommand
                    certMessage:(NSString * _Nonnull)certMessage {
    BleByteMatrix *cByteMatrix = createTboxMessageV3With((BLEBoxCommand)controlCommand, certMessage.cString, controlId, certMessage.length);
    if (cByteMatrix != NULL) {
        NSMutableArray *sendParams = [NSMutableArray array];
        NSUInteger length = cByteMatrix->length;
        size_t *sizes = cByteMatrix->sizes;
        for (NSUInteger i = 0; i < length; i++) {
            size_t rowSize = sizes[i];
            void *rowPtr = cByteMatrix->data[i];
            if (rowSize != 0 && rowPtr != NULL) {
                NSData *data = [NSData dataWithBytes:rowPtr length:rowSize];
                [sendParams addObject:data];
            }
        }
        freeBleByteMatrix(cByteMatrix);
        DLogTagInfo(@"XPBLEDataMake", @"提取单元测试：\nNSData *result = [XPBleKeyV3DataProcessor createTboxMessageV3:%@ controlCommand:%@ certMessage:@\"%@\"];\n"
            "NSString * testResultToHexStr = [result hexString];\n"
            "NSString * testResultHexRight = @\"%@\"; // 当次执行结果 \n"
            "XCTAssertTrue([testResultToHexStr isEqualToString:testResultHexRight]);\n",
                    @(controlId), @(controlCommand), certMessage, [sendParams.firstObject hexString]);

        return sendParams.firstObject;
    } else {
        DLogTagInfo(@"XPBLEDataMake", @"createTboxMessageV3 result:<nil> [XPBleKeyV3DataProcessor createTboxMessageV3:%@ controlCommand:%@ certMessage:@\"%@\"]", @(controlId), @(controlCommand), certMessage);
        return nil;
    }
}

