                    "NSString * testResultHexRight = @\"%@\"; // 当次执行结果 \n"
                    "XCTAssertTrue([testResultToHexStr isEqualToString:testResultHexRight]);\n",
                    @(isEncrypt), @(controlId), @(cmd), [sessionKey hexString], [resultData hexString]);

        return resultData;
    } catch (const std::exception& ) {
        DLogTagInfo(@"XPBLEDataMake", @"generateRescueRkeControlRequestData failed with params: isEncrypt = %@, controlId = %@, cmd = %@, sessionKey = %@", @(isEncrypt), @(controlId), @(cmd), [sessionKey hexString]);
    }
    return nil;
}

